#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <limits.h>
#include <stdbool.h>
#include <string.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	// Parallelize over the number of queries (blocks)
	// Do not create threads for every key position (local_size) as that causes overflow
	#pragma omp parallel for num_threads(cores_arg > 0 ? cores_arg : omp_get_max_threads())
	int bid = 0;
	for(bid = 0; bid < count; bid++){
		long current_knode = currKnode[bid];
		long offset_val = offset[bid];
		int key_val = keys[bid];

		int i;
		for(i = 0; i < maxheight; i++){
			// Find the correct child index by scanning keys
			// This replaces the parallel scan over thid in OpenCL
			int thid = 0;
			int found = 0;
			// Scan keys to find the range [keys[thid], keys[thid+1]) containing key_val
			for(thid = 0; thid < order; thid++){
				if((knodes[current_knode].keys[thid] <= key_val) && (knodes[current_knode].keys[thid+1] > key_val)){
					if(knodes[offset_val].indices[thid] < knodes_elem){
						offset_val = knodes[offset_val].indices[thid];
					}
					found = 1;
					break;
				}
			}

			// Update current knode for next level
			current_knode = offset_val;
		}

		// Final lookup
		int thid = 0;
		for(thid = 0; thid < order; thid++){
			if(knodes[current_knode].keys[thid] == key_val){
				ans[bid].value = records[knodes[current_knode].indices[thid]].value;
				break;
			}
		}

		// Update global arrays if needed (though local vars were used for logic)
		// The original code updated currKnodeD[bid] in the loop, but since we are done, 
		// we just ensure ans is set.
	}
}

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
	int cores = omp_get_max_threads();
	if(cores == 0) cores = 1;
	kernel_cpu(cores, records, knodes, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);
}

