	int indices [DEFAULT_ORDER_2 + 1];
	int  keys [DEFAULT_ORDER_2 + 1];
	bool is_leaf;
	int num_keys;
} knode;

void 
kernel_gpu_opencl_wrapper_2(knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *recstart,
							int *reclength)
{

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	size_t local_work_size = 1024 > order ? order : 1024;
	size_t global_work_size = count * local_work_size;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

#pragma omp parallel
{
	int thid = omp_get_thread_num();
	int bid = thid / local_work_size;
	int local_id = thid % local_work_size;

	if (bid < count) {

		long local_currKnode = currKnode[bid];
		long local_offset = offset[bid];
		long local_lastKnode = lastKnode[bid];
		long local_offset_2 = offset_2[bid];
		int local_start = start[bid];
		int local_end = end[bid];

		int i;
		for(i = 0; i < maxheight; i++){

			if((knodes[local_currKnode].keys[local_id] <= local_start) && (knodes[local_currKnode].keys[local_id+1] > local_start)){

				if(knodes[local_currKnode].indices[local_id] < knodes_elem){
					local_offset = knodes[local_currKnode].indices[local_id];
				}
			}
			if((knodes[local_lastKnode].keys[local_id] <= local_end) && (knodes[local_lastKnode].keys[local_id+1] > local_end)){

				if(knodes[local_lastKnode].indices[local_id] < knodes_elem){
					local_offset_2 = knodes[local_lastKnode].indices[local_id];
				}
			}

#pragma omp barrier

			if(0 == local_id){
				local_currKnode = local_offset;
				local_lastKnode = local_offset_2;
			}

#pragma omp barrier
		}

		if(knodes[local_currKnode].keys[local_id] == local_start){
			recstart[bid] = knodes[local_currKnode].indices[local_id];
		}

#pragma omp barrier

		if(knodes[local_lastKnode].keys[local_id] == local_end){
