void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  float sum;
  int j, k;


  l1[0] = 1.0;
  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(conn, n1, n2, l1) private(k, j, sum) schedule(static)

  for (j = 1; j <= n2; j++) {


