        int ty = block_idx % HEIGHT;
        for (int tx = 0; tx < WIDTH; tx++) {
            bpnn_adjust_weights_ocl(hidden_delta_ptr,
                                    hid,
                                    input_units_ptr,
                                    in,
                                    input_weights_one_dim,
                                    input_weights_prev_one_dim,
                                    by,
                                    tx,
                                    ty);
        }
    }

    m = 0;
    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            net->input_weights[k][j] = input_weights_one_dim[m];
            net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
            m++;
        }
    }

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);
	free(input_node_local);
	free(weight_matrix_local);

    return 0;
}

