void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  float sum;
  int j, k;
  l1[0] = 1.0f;
  #pragma omp parallel for shared(conn, l1, l2, n1, n2) private(j, k, sum)
  for (j = 1; j <= n2; j++) {
    sum = 0.0f;
    for (k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash(sum);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  int j;
  float o, t, errsum = 0.0f;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  int j, k;
  float h, sum, errsum = 0.0f;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  float new_dw;
  int k, j;
  ly[0] = 1.0f;
  #pragma omp parallel for shared(w, oldw, delta, ly) private(j, k, new_dw)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]);
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

void bpnn_feedforward(BPNN *net) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  float out_err, hid_err;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

void bpnn_layerforward_ocl(float *input_cuda,
                           float *output_hidden_cuda,
                           float *input_hidden_cuda,
                           float *hidden_partial_sum,
                           int in,
                           int hid,
                           int num_blocks) 
{
    int by, tx, ty;
    float input_node[HEIGHT];
    float weight_matrix[HEIGHT * WIDTH];

    #pragma omp parallel for collapse(2) private(by, tx, ty, input_node, weight_matrix)
    for (by = 0; by < num_blocks; by++) {
        for (ty = 0; ty < HEIGHT; ty++) {
            for (tx = 0; tx < WIDTH; tx++) {

                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                int index_in = HEIGHT * by + ty + 1;

                if (tx == 0) {
                    input_node[ty] = input_cuda[index_in];
                }

                weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];

                weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] * input_node[ty];

                for (int i = 1; i <= HEIGHT; i = i * 2) {
                    int power_two = i;
                    if (ty % power_two == 0) {
                        int partner_idx = (ty + power_two / 2);
                        if (partner_idx < HEIGHT) {
                            weight_matrix[ty * WIDTH + tx] += weight_matrix[partner_idx * WIDTH + tx];
                        }
                    }
                }

                input_hidden_cuda[index] = weight_matrix[ty * WIDTH + tx];

                if (tx == 0) {
                    hidden_partial_sum[by * hid + ty] = weight_matrix[0 * WIDTH + ty];
                }
            }
        }
    }
}

void bpnn_adjust_weights_ocl(float *delta,
                             int hid,
                             float *ly,
                             int in,
                             float *w,
                             float *oldw,
                             int num_blocks)
{
    int by, tx, ty;

    #pragma omp parallel for collapse(2) private(by, tx, ty)
    for (by = 0; by < num_blocks; by++) {
        for (ty = 0; ty < HEIGHT; ty++) {
            for (tx = 0; tx < WIDTH; tx++) {

                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                int index_y = HEIGHT * by + ty + 1;
                int index_x = tx + 1;

                float delta_val = ETA * delta[index_x] * ly[index_y];
                float momentum_val = MOMENTUM * oldw[index];
                float new_dw = delta_val + momentum_val;

                w[index] += new_dw;
                oldw[index] = new_dw;

                if (ty == 0 && by == 0) {
                    float delta_val_x = ETA * delta[index_x];
                    float momentum_val_x = MOMENTUM * oldw[index_x];
                    float new_dw_x = delta_val_x + momentum_val_x;

                    w[index_x] += new_dw_x;
                    oldw[index_x] = new_dw_x;
                }
            }
        }
    }
}

static int bpnn_train_kernel(BPNN *net, float *eo, float *eh) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  float out_err, hid_err;
  int num_blocks = in / BLOCK_SIZE;
  float *partial_sum;
  float sum;
  int j, k;

  float *input_weights_one_dim = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));
  float *input_weights_prev_one_dim = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));
  partial_sum = (float *)malloc(num_blocks * WIDTH * sizeof(float));

  int m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
      m++;
    }
  }

  printf("Performing CPU computation\n");

  bpnn_layerforward_ocl(net->input_units, net->output_units, input_weights_one_dim, partial_sum, in, hid, num_blocks);

  for (j = 1; j <= hid; j++) {
    sum = 0.0f;
    for (k = 0; k < num_blocks; k++) {
      sum += partial_sum[k * hid + j - 1];
    }
    sum += net->input_weights[0][j];
    net->hidden_units[j] = squash(sum);
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  bpnn_adjust_weights_ocl(net->hidden_delta, hid, net->input_units, in, input_weights_one_dim, input_weights_prev_one_dim, num_blocks);

  m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      net->input_weights[k][j] = input_weights_one_dim[m];
      net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
      m++;
    }
  }

  *eo = out_err;
  *eh = hid_err;

  free(input_weights_one_dim);
  free(input_weights_prev_one_dim);
  free(partial_sum);

  return 0;
}

