        for(int tid=0; tid< no_of_nodes ; tid++ ) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid]=true;
                h_graph_visited[tid]=true;
                stop=true;
                h_updating_graph_mask[tid]=false;
            }
        }
        k++;
    } while(stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, \
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, \
                 char *h_graph_visited, int *h_cost)
{
    char h_over;

    // In OpenMP version, we directly operate on host memory
    // No need for device memory allocation

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
    // Simulate init time calculation
    init_time = 0;
#endif

    // No malloc for device, using host pointers directly

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = 0;
#endif

    // No H2D copy needed, data is already in host memory

#ifdef PROFILING
    timer kernel_timer;
    double kernel_time = 0.0;
    kernel_timer.reset();
    kernel_timer.start();
#endif

    do {
        h_over = false;

        // BFS_1 equivalent: Process active nodes
        #pragma omp parallel for
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if(h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                for(int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if(!h_graph_visited[id]) {
                        h_cost[id] = h_cost[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        // BFS_2 equivalent: Update visited and check if any node was updated
        char local_over = false;
        #pragma omp parallel for
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if(h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                h_updating_graph_mask[tid] = false;
                local_over = true;
            }
        }

        if(local_over) h_over = true;

    } while(h_over);

#ifdef PROFILING
    kernel_timer.stop();
    kernel_time = kernel_timer.getTimeInSeconds();
#endif

    // No D2H copy needed, data is already in host memory

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILING
    std::cout<<"kernel time(s):"<<kernel_time<<std::endl;
#endif

    // No free needed for device memory

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = 0;
    total_time = 0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return ;
}

