inline void timer::reset() { total_time = 0; count = 0; }
inline timer::timer(const char *name) : name(name), write_on_exit(0) { reset(); }
inline timer::timer(const char *name, std::ostream &write_on_exit) : name(name), write_on_exit(&write_on_exit) { reset(); }
inline timer::~timer() {}
inline void timer::start() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "subl %%eax, %0\n\t" "sbbl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#else
    total_time = 0; // Fallback
#endif
}
inline void timer::stop() {
#if (defined __GNUC__ || defined __INTEL_COMPILER) && (defined __i386 || defined __x86_64)
    asm volatile ("rdtsc\n\t" "addl %%eax, %0\n\t" "adcl %%edx, %1" : "+m" (low), "+m" (high) : : "eax", "edx");
#else
    total_time = 1; // Fallback
#endif
    ++ count;
}
inline double timer::getTimeInSeconds() {
    double total = static_cast<double>(total_time);
    double speed = get_CPU_speed_in_MHz();
    if (speed == 0.0) return 0.0;
    return (total / 1000000.0) / speed;
}
double timer::CPU_speed_in_MHz = timer::get_CPU_speed_in_MHz();
double timer::get_CPU_speed_in_MHz() {
#if defined __linux__
    std::ifstream infile("/proc/cpuinfo");
    char buffer[256], *colon;
    while (infile.good()) {
        infile.getline(buffer, 256);
        if (strncmp("cpu MHz", buffer, 7) == 0 && (colon = strchr(buffer, ':')) != 0)
            return atof(colon + 2);
    }
#endif
    return 0.0;
}
