struct Node {
    int starting;
    int no_of_edges;
};

// OpenMP version of BFS_1
void bfs_1_omp(const Node* graph_nodes, const int* graph_edges, char* graph_mask, 
               char* updating_graph_mask, char* graph_visited, int* cost, int no_of_nodes) {
    #pragma omp parallel for
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (graph_mask[tid]) {
            graph_mask[tid] = false;
            int start = graph_nodes[tid].starting;
            int end = start + graph_nodes[tid].no_of_edges;
            for (int i = start; i < end; i++) {
                int id = graph_edges[i];
                if (!graph_visited[id]) {
                    cost[id] = cost[tid] + 1;
                    updating_graph_mask[id] = true;
                }
            }
        }
    }
}

// OpenMP version of BFS_2
bool bfs_2_omp(char* graph_mask, char* updating_graph_mask, char* graph_visited, int no_of_nodes) {
    bool over = false;
    #pragma omp parallel for
    for (int tid = 0; tid < no_of_nodes; tid++) {
        if (updating_graph_mask[tid]) {
            graph_mask[tid] = true;
            graph_visited[tid] = true;
            updating_graph_mask[tid] = false;
            over = true;
        }
    }
    return over;
}

