			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			ff_variable[VAR_DENSITY] = float(1.4);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			FLOAT3 ff_velocity;
			ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
			ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
			ff_velocity.z = 0.0f;

			ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity.x;
			ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity.y;
			ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity.z;

			ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			FLOAT3 h_ff_momentum;
			h_ff_momentum.x = ff_variable[VAR_MOMENTUM+0];
			h_ff_momentum.y = ff_variable[VAR_MOMENTUM+1];
			h_ff_momentum.z = ff_variable[VAR_MOMENTUM+2];

			compute_flux_contribution_main(ff_variable[VAR_DENSITY], h_ff_momentum, ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, ff_flux_contribution_momentum_x[0], ff_flux_contribution_momentum_y[0], ff_flux_contribution_momentum_z[0], ff_flux_contribution_density_energy[0]);
		}

		int nel;
		int nelr;

		float* areas = nullptr;
		int* elements_surrounding_elements = nullptr;
		float* normals = nullptr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;
			float* h_areas = new float[nelr];
			int* h_elements_surrounding_elements = new int[nelr*NNB];
			float* h_normals = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> h_areas[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> h_elements_surrounding_elements[i + j*nelr];
					if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
					h_elements_surrounding_elements[i + j*nelr]--; 

					for(int k = 0; k < NDIM; k++)
					{
						file >> h_normals[i + (j + k*NNB)*nelr];
						h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				h_areas[i] = h_areas[last];
				for(int j = 0; j < NNB; j++)
				{
					h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];	
					for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
				}
			}

			areas = h_areas;
			elements_surrounding_elements = h_elements_surrounding_elements;
			normals = h_normals;
		}

		float* variables = new float[nelr*NVAR];				
		float* old_variables = new float[nelr*NVAR];   
		float* fluxes = new float[nelr*NVAR];
		float* step_factors = new float[nelr]; 

		// Initialize variables
		initialize_variables(variables, ff_variable, nelr);			
		initialize_variables(old_variables, ff_variable, nelr);	
		initialize_variables(fluxes, ff_variable, nelr);		

		// Memset step_factors to 0
		for(int i=0; i<nelr; i++) step_factors[i] = 0.0f;

		std::cout << "Starting..." << std::endl;

		const int iterations = 2000;

		for(int i = 0; i < iterations; i++){
			// Copy variables to old_variables
			#pragma omp parallel for
			for(int k=0; k<nelr*NVAR; k++) old_variables[k] = variables[k];

			compute_step_factor(variables, areas, step_factors, nelr);
			for(int j = 0; j < RK; j++){
				compute_flux(elements_surrounding_elements, normals, variables, ff_variable, fluxes, ff_flux_contribution_density_energy, \
				ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, nelr);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
		}

		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;

		std::cout << "Cleaning up..." << std::endl;

		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
		delete[] areas;
		delete[] elements_surrounding_elements;
		delete[] normals;
		delete[] variables;
		delete[] old_variables;
		delete[] fluxes;
		delete[] step_factors;

		std::cout << "Done..." << std::endl;
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;		
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;		
	}

	return 0;
}

