		}
	}

	{
		std::ofstream file("density_energy.txt");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
	}
}

inline void compute_flux_contribution_host(float& density, FLOAT3& momentum, float& density_energy, float& pressure, FLOAT3& velocity, FLOAT3& fc_momentum_x, FLOAT3& fc_momentum_y, FLOAT3& fc_momentum_z, FLOAT3& fc_density_energy)
{
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;

	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

int main(int argc, char** argv){
  printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (argc < 2){
		std::cout << "specify data file name and [device type] [device id]" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];

	float* ff_variable = new float[NVAR];
	FLOAT3* ff_flux_contribution_momentum_x = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_momentum_y = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_momentum_z = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_density_energy = new FLOAT3[1];

	float* areas;
	int* elements_surrounding_elements;
	float* normals;
	float* variables;
	float* old_variables;
	float* fluxes;
	float* step_factors;

	try{		
		{
			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			ff_variable[VAR_DENSITY] = float(1.4);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			FLOAT3 ff_velocity;
			ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
			ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
			ff_velocity.z = 0.0f;

			ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity.x;
			ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity.y;
			ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity.z;

			ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			FLOAT3 h_ff_momentum;
			h_ff_momentum.x = ff_variable[VAR_MOMENTUM+0];
			h_ff_momentum.y = ff_variable[VAR_MOMENTUM+1];
			h_ff_momentum.z = ff_variable[VAR_MOMENTUM+2];

			compute_flux_contribution_host(ff_variable[VAR_DENSITY], h_ff_momentum, ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, ff_flux_contribution_momentum_x[0], ff_flux_contribution_momentum_y[0], ff_flux_contribution_momentum_z[0], ff_flux_contribution_density_energy[0]);
		}
		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;
			float* h_areas = new float[nelr];
			int* h_elements_surrounding_elements = new int[nelr*NNB];
			float* h_normals = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> h_areas[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> h_elements_surrounding_elements[i + j*nelr];
					if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
					h_elements_surrounding_elements[i + j*nelr]--; 

					for(int k = 0; k < NDIM; k++)
					{
						file >> h_normals[i + (j + k*NNB)*nelr];
						h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				h_areas[i] = h_areas[last];
				for(int j = 0; j < NNB; j++)
				{
					h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];	
					for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
				}
			}

			areas = new float[nelr];
			std::copy(h_areas, h_areas + nelr, areas);

			elements_surrounding_elements = new int[nelr*NNB];
			std::copy(h_elements_surrounding_elements, h_elements_surrounding_elements + nelr*NNB, elements_surrounding_elements);

			normals = new float[nelr*NDIM*NNB];
			std::copy(h_normals, h_normals + nelr*NDIM*NNB, normals);

			delete[] h_areas;
			delete[] h_elements_surrounding_elements;
			delete[] h_normals;
		}

		variables = new float[nelr*NVAR];				
		int tp = 0;
		initialize_variables(variables, ff_variable, nelr);			
		old_variables = new float[nelr*NVAR];   
		fluxes = new float[nelr*NVAR];
		step_factors = new float[nelr]; 

		initialize_variables(old_variables, ff_variable, nelr);	
		initialize_variables(fluxes, ff_variable, nelr);		
		memset_kernel((char*)step_factors, 0, sizeof(float)*nelr);

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			std::copy(variables, variables + nelr*NVAR, old_variables);

			compute_step_factor(variables, areas, step_factors, nelr);
			for(int j = 0; j < RK; j++){
				compute_flux(elements_surrounding_elements, normals, variables, ff_variable, fluxes, ff_flux_contribution_density_energy, \
				ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, nelr);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
		}

		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;
		std::cout << "Cleaning up..." << std::endl;

		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
		delete[] areas;
		delete[] elements_surrounding_elements;
		delete[] normals;
		delete[] variables;
		delete[] old_variables;
		delete[] fluxes;
		delete[] step_factors;

		std::cout << "Done..." << std::endl;
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;		
		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
		delete[] areas;
		delete[] elements_surrounding_elements;
		delete[] normals;
		delete[] variables;
		delete[] old_variables;
		delete[] fluxes;
		delete[] step_factors;
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;		
		delete[] ff_variable;
		delete[] ff_flux_contribution_momentum_x;
		delete[] ff_flux_contribution_momentum_y;
		delete[] ff_flux_contribution_momentum_z;
		delete[] ff_flux_contribution_density_energy;
		delete[] areas;
		delete[] elements_surrounding_elements;
		delete[] normals;
		delete[] variables;
		delete[] old_variables;
		delete[] fluxes;
		delete[] step_factors;
	}

	return 0;
}

