		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++)
		{
			for(int j = 0; j != NDIM; j++)
				file << variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
			file << std::endl;
		}
	}

	{
		std::ofstream file("density_energy.txt");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
	}
}

inline void compute_flux_contribution_host(float& density, FLOAT3& momentum, float& density_energy, float& pressure, FLOAT3& velocity, FLOAT3& fc_momentum_x, FLOAT3& fc_momentum_y, FLOAT3& fc_momentum_z, FLOAT3& fc_density_energy)
{
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;

	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

int main(int argc, char** argv){
  printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (2 > argc){
		std::cout << "specify data file name" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];

	float* ff_variable_host = new float[NVAR];
	FLOAT3* ff_flux_contribution_momentum_x_host = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_momentum_y_host = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_momentum_z_host = new FLOAT3[1];
	FLOAT3* ff_flux_contribution_density_energy_host = new FLOAT3[1];

	float* areas_host;
	int* elements_surrounding_elements_host;
	float* normals_host;
	float* variables_host;
	float* old_variables_host;
	float* fluxes_host;
	float* step_factors_host;

	try{		
		{
			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			ff_variable_host[VAR_DENSITY] = float(1.4);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable_host[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			FLOAT3 ff_velocity;
			ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
			ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
			ff_velocity.z = 0.0f;

			ff_variable_host[VAR_MOMENTUM+0] = ff_variable_host[VAR_DENSITY] * ff_velocity.x;
			ff_variable_host[VAR_MOMENTUM+1] = ff_variable_host[VAR_DENSITY] * ff_velocity.y;
			ff_variable_host[VAR_MOMENTUM+2] = ff_variable_host[VAR_DENSITY] * ff_velocity.z;

			ff_variable_host[VAR_DENSITY_ENERGY] = ff_variable_host[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			FLOAT3 h_ff_momentum;
			h_ff_momentum.x = ff_variable_host[VAR_MOMENTUM+0];
			h_ff_momentum.y = ff_variable_host[VAR_MOMENTUM+1];
			h_ff_momentum.z = ff_variable_host[VAR_MOMENTUM+2];

			compute_flux_contribution_host(ff_variable_host[VAR_DENSITY], h_ff_momentum, ff_variable_host[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, 
				ff_flux_contribution_momentum_x_host[0], ff_flux_contribution_momentum_y_host[0], ff_flux_contribution_momentum_z_host[0], ff_flux_contribution_density_energy_host[0]);
		}

		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file){
				throw(std::string("can not find/open file!"));
			}
			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;

			areas_host = new float[nelr];
			elements_surrounding_elements_host = new int[nelr*NNB];
			normals_host = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++)
			{
				file >> areas_host[i];
				for(int j = 0; j < NNB; j++)
				{
					file >> elements_surrounding_elements_host[i + j*nelr];
					if(0 > elements_surrounding_elements_host[i+j*nelr]) elements_surrounding_elements_host[i+j*nelr] = -1;
					elements_surrounding_elements_host[i + j*nelr]--; 

					for(int k = 0; k < NDIM; k++)
					{
						file >> normals_host[i + (j + k*NNB)*nelr];
						normals_host[i + (j + k*NNB)*nelr] = -normals_host[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++)
			{
				areas_host[i] = areas_host[last];
				for(int j = 0; j < NNB; j++)
				{
					elements_surrounding_elements_host[i + j*nelr] = elements_surrounding_elements_host[last + j*nelr];	
					for(int k = 0; k < NDIM; k++) normals_host[i + (j + k*NNB)*nelr] = normals_host[last + (j + k*NNB)*nelr];
				}
			}
		}

		variables_host = new float[nelr*NVAR];				
		old_variables_host = new float[nelr*NVAR];   
		fluxes_host = new float[nelr*NVAR];
		step_factors_host = new float[nelr]; 

		initialize_variables(variables_host, ff_variable_host, nelr);			
		initialize_variables(old_variables_host, ff_variable_host, nelr);	
		initialize_variables(fluxes_host, ff_variable_host, nelr);		

		for(int i = 0; i < nelr; i++) step_factors_host[i] = 0.0f;

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			#pragma omp parallel for
			for(int k=0; k<nelr*NVAR; k++) old_variables_host[k] = variables_host[k];

			compute_step_factor(variables_host, areas_host, step_factors_host, nelr);
			for(int j = 0; j < RK; j++){
				compute_flux(elements_surrounding_elements_host, normals_host, variables_host, ff_variable_host, fluxes_host, 
					ff_flux_contribution_density_energy_host, ff_flux_contribution_momentum_x_host, 
					ff_flux_contribution_momentum_y_host, ff_flux_contribution_momentum_z_host, nelr);

				time_step(j, nelr, old_variables_host, variables_host, step_factors_host, fluxes_host);
			}
		}

		std::cout << "Saving solution..." << std::endl;
		dump(variables_host, nel, nelr);
		std::cout << "Saved solution..." << std::endl;

		std::cout << "Cleaning up..." << std::endl;

		delete[] ff_variable_host;
		delete[] ff_flux_contribution_momentum_x_host;
		delete[] ff_flux_contribution_momentum_y_host;
		delete[] ff_flux_contribution_momentum_z_host;
		delete[] ff_flux_contribution_density_energy_host;
		delete[] areas_host;
		delete[] elements_surrounding_elements_host;
		delete[] normals_host;
		delete[] variables_host;
		delete[] old_variables_host;
		delete[] fluxes_host;
		delete[] step_factors_host;

		std::cout << "Done..." << std::endl;
	}
	catch(std::string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;		
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;		
	}

	return 0;
}

