    printf("frame progress: ");
    fflush(NULL);

    for(frame_no=0; frame_no<common.frames_processed; frame_no++){
        frame = get_frame(frames, frame_no, 0, 0, 1);

        fp* d_frame = frame; 

        #pragma omp parallel for
        for(int bx = 0; bx < common.allPoints; bx++){
            kernel_gpu_opencl(	
                common, 
                d_frame, 
                frame_no, 
                endoRow, 
                endoCol, 
                tEndoRowLoc, 
                tEndoColLoc, 
                epiRow, 
                epiCol, 
                tEpiRowLoc, 
                tEpiColLoc, 
                d_endoT, 
                d_epiT, 
                d_in2_all, 
                d_conv_all, 
                d_in2_pad_cumv_all, 
                d_in2_pad_cumv_sel_all, 
                d_in2_sub_cumh_all, 
