#endif

            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                row = (ei_new + 1) % d_common.in2_sub2_rows - 1;
                col = (ei_new + 1) / d_common.in2_sub2_rows + 1 - 1;
                if ((ei_new + 1) % d_common.in2_sub2_rows == 0) {
                    row = d_common.in2_sub2_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in2_sub2_elem; i++) {
                    checksum_global[21] += d_unique_d_in2_sqr_sub2[i];
                }
            }
#endif

            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_in2_sub_cumh_sel[ei_new] - d_unique_d_in2_sqr_sub2[ei_new];
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in2_sub2_elem; i++) {
                    checksum_global[22] += d_unique_d_in2_sqr_sub2[i];
                }
            }
#endif

            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                temp = d_unique_d_in2_sub2[ei_new];
                temp2 = d_unique_d_in2_sqr_sub2[ei_new] - (temp * temp / d_common.in_elem);
                if (temp2 < 0) temp2 = 0;
                d_unique_d_in2_sqr_sub2[ei_new] = sqrt(temp2);
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in2_sub2_elem; i++) {
                    checksum_global[23] += d_unique_d_in2_sqr_sub2[i];
                }
            }
#endif

            for (ei_new = 0; ei_new < d_common.in_sqr_elem; ei_new++) {
                temp = d_in[ei_new];
                d_unique_d_in_sqr[ei_new] = temp * temp;
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in_sqr_elem; i++) {
                    checksum_global[24] += d_unique_d_in_sqr[i];
                }
            }
#endif

            for (ei_new = 0; ei_new < d_common.in_cols; ei_new++) {
                sum = 0;
                for (i = 0; i < d_common.in_rows; i++) {
                    sum += d_in[ei_new * d_common.in_rows + i];
                }
                in_partial_sum[ei_new] = sum;
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in_cols; i++) {
                    checksum_global[25] += in_partial_sum[i];
                }
            }
#endif

            for (ei_new = 0; ei_new < d_common.in_sqr_rows; ei_new++) {
                sum = 0;
                for (i = 0; i < d_common.in_sqr_cols; i++) {
                    sum += d_unique_d_in_sqr[ei_new + d_common.in_sqr_rows * i];
                }
                in_sqr_partial_sum[ei_new] = sum;
            }

#ifdef TEST_CHECKSUM
            if (bx == 0) {
                for (i = 0; i < d_common.in_sqr_rows; i++) {
                    checksum_global[26] += in_sqr_partial_sum[i];
                }
            }
#endif

            if (tx == 0) {
                in_final_sum[0] = 0;
                for (i = 0; i < d_common.in_cols; i++) {
                    in_final_sum[0] += in_partial_sum[i];
                }
            } else if (tx == 1) {
                in_sqr_final_sum[0] = 0;
                for (i = 0; i < d_common.in_sqr_cols; i++) {
                    in_sqr_final_sum[0] += in_sqr_partial_sum[i];
