void hotspotOpt1(float *p, float *tmp_17, float *x_2, float elem_16,
                 int x_4, int item_8, int data_7,
                 float item_1, float val_6, 
                 float var_9, float item_3,
                 float item_15, float elem_5, 
                 float x_11) 
{
  float x_13 = 80.0;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < item_8; j++) {
    for (int i = 0; i < x_4; i++) {
      int c = i + j * x_4;
      int item_0 = x_4 * item_8;

      int W = (0 == i)        ? c : c - 1;
      int E = (x_4-1 == i)     ? c : c + 1;
      int N = (0 == j)        ? c : c - x_4;
      int S = (item_8-1 == j)     ? c : c + x_4;

      float data_14, tmp_10, data_12;
      data_14 = tmp_10 = tmp_17[c];
      data_12 = tmp_17[c+item_0];
      x_2[c] = x_11 * tmp_10 + val_6 * tmp_17[W] + item_1 * tmp_17[E] + item_3 * tmp_17[S]
        + var_9 * tmp_17[N] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c] + item_15 * x_13;
      int c_curr = c + item_0;
      int W_curr = W + item_0;
      int E_curr = E + item_0;
      int N_curr = N + item_0;
      int S_curr = S + item_0;

      for (int k = 1; data_7-1 > k; ++k) {
          data_14 = tmp_10;
          tmp_10 = data_12;
          data_12 = tmp_17[c_curr+item_0];
          x_2[c_curr] = x_11 * tmp_10 + val_6 * tmp_17[W_curr] + item_1 * tmp_17[E_curr] + item_3 * tmp_17[S_curr]
            + var_9 * tmp_17[N_curr] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c_curr] + item_15 * x_13;
          c_curr += item_0;
          W_curr += item_0;
          E_curr += item_0;
          N_curr += item_0;
          S_curr += item_0;
      }
      data_14 = tmp_10;
      tmp_10 = data_12;
      x_2[c_curr] = x_11 * tmp_10 + val_6 * tmp_17[W_curr] + item_1 * tmp_17[E_curr] + item_3 * tmp_17[S_curr]
        + var_9 * tmp_17[N_curr] + elem_5 * data_14 + item_15 * data_12 + elem_16 * p[c_curr] + item_15 * x_13;
    }
  }
}

