    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; i<nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    do {
        delta = 0.0;

        delta = (float) kmeansOCL(feature,
                                   nfeatures,
                                   npoints,
                                   nclusters,
                                   membership,
                                   clusters,
                                   new_centers_len,
                                   new_centers);

        for (i=0; i<nclusters; i++) {
            for (j=0; j<nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;
            }
            new_centers_len[i] = 0;
        }
        c++;
    } while ((delta > threshold) && (loop++ < 500));
    printf("iterated %d times\n", c);
    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

int kmeansOCL(float **feature,
              int     n_features,
              int     n_points,
              int     n_clusters,
              int    *membership,
              float **clusters,
              int     *new_centers_len,
              float  **new_centers)
{
    int delta = 0;
    int i, j, k;

    int *membership_local = (int*) malloc(n_points * sizeof(int));

    #pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < n_points; point_id++) {
        int index = 0;
        float min_dist = FLT_MAX;

        for (int i = 0; i < n_clusters; i++) {
            float dist = 0;
            float ans = 0;
            for (int l = 0; l < n_features; l++) {
                float diff = feature[point_id][l] - clusters[i][l];
                ans += diff * diff;
            }
            dist = ans;
            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }
        membership_local[point_id] = index;
    }

    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < n_points; tid++) {
        int cluster_id = membership_local[tid];
        new_centers_len[cluster_id]++;
        if (membership_local[tid] != membership[tid]) {
            delta++;
            membership[tid] = membership_local[tid];
        }
        for (j = 0; j < n_features; j++) {
            new_centers[cluster_id][j] += feature[tid][j];
        }
    }

    free(membership_local);
    return delta;
}

