    k02 = k20 / Kd02;
    k42 = 500;
    k24 = k42 / Kd24;

    k0Boff = 0.0014;
    k0Bon = k0Boff / 0.2;
    k2Boff = k0Boff / 100;
    k2Bon = k0Bon;
    k4Boff = k2Boff;
    k4Bon = k0Bon;

    k20B = k20 / 100;
    k02B = k02;
    k42B = k42;
