}

void kernel_gpu_opencl(int timeinst, fp *d_initvalu, fp *d_finavalu, fp *d_params, fp *d_com) {
    fp CaDyad, CaSL, CaCyt;
    fp JCaDyad, JCaSL, JCaCyt;
    int i;

    kernel_ecc((fp)timeinst, d_initvalu, d_finavalu, 0, d_params);

    CaDyad = d_initvalu[35] * 1e3;
    JCaDyad = cam((fp)timeinst, d_initvalu, 46, d_params, 0, CaDyad);
    for(i=0; i<15; i++) d_finavalu[46+i] = d_initvalu[46+i];

    CaSL = d_initvalu[36] * 1e3;
    JCaSL = cam((fp)timeinst, d_initvalu, 61, d_params, 5, CaSL);
    for(i=0; i<15; i++) d_finavalu[61+i] = d_initvalu[61+i];

    CaCyt = d_initvalu[37] * 1e3;
