int solver(fp **y,
           fp *x,
           int xmax,
           fp *params,
           fp *com,
           fp *d_initvalu,
           fp *d_finavalu,
           fp *d_params,
           fp *d_com) {

    fp err_exponent;
    int error;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp *err = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *scale = (fp *)malloc(EQUATIONS * sizeof(fp));
    fp *yy = (fp *)malloc(EQUATIONS * sizeof(fp));

    int i, j, k;

    err_exponent = 1.0 / 7.0;
    h_init = 1;
    h = h_init;
    xmin = 0;
    tolerance = 10 / (fp)(xmax - xmin);

    x[0] = 0;

    if (xmin > xmax || 0.0 >= h) {
        return -2;
    }

    if (xmin == xmax) {
        return 0;
    }

    if ((xmax - xmin) < h) {
        h = (fp)xmax - (fp)xmin;
    }

    printf("Time Steps: ");
    fflush(stdout);

    for (k = 1; xmax >= k; k++) {

        x[k] = k - 1;
        h = h_init;

        scale_fina = 1.0;

        for (j = 0; j < 12; j++) {

            error = 0;
            outside = 0;
            scale_min = 4.0;

            embedded_fehlberg_7_8(x[k],
                                  h,
                                  y[k - 1],
                                  y[k],
                                  err,
                                  params,
                                  com,
                                  d_initvalu,
                                  d_finavalu,
                                  d_params,
                                  d_com);

            for (i = 0; i < EQUATIONS; i++) {
                if (err[i] > 0) {
                    error = 1;
                }
            }
            if (1 != error) {
                scale_fina = 4.0;
                break;
            }

            for (i = 0; i < EQUATIONS; i++) {
                if (y[k - 1][i] == 0.0) {
                    yy[i] = tolerance;
                } else {
                    yy[i] = fabs(y[k - 1][i]);
                }
                scale[i] = 0.8 * pow(tolerance * yy[i] / err[i], err_exponent);
                if (scale_min > scale[i]) {
                    scale_min = scale[i];
                }
            }
            scale_fina = (scale_min > 0.125 ? scale_min : 0.125);
            if (scale_fina > 4.0) scale_fina = 4.0;

            for (i = 0; i < EQUATIONS; i++) {
                if (err[i] > (tolerance * yy[i])) {
                    outside = 1;
                }
            }
            if (0 == outside) {
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9) {
                h = 0.9;
            }

            if (x[k] + h > (fp)xmax) {
                h = (fp)xmax - x[k];
            } else if (x[k] + h + 0.5 * h > (fp)xmax) {
                h = 0.5 * h;
            }
        }

        x[k] = x[k] + h;

        if (12 <= j) {
            return -1;
        }

        printf("%d ", k);
        fflush(stdout);
    }

    printf("\n");
    fflush(stdout);

    free(err);
    free(scale);
    free(yy);

    return 0;
}

int kernel_gpu_opencl_wrapper(int xmax,
                              int workload,
                              fp ***y,
                              fp **x,
                              fp **params,
                              fp *com) {

    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
    long long timeother;

    time0 = 0; 

    int i;

    int d_initvalu_mem;
    d_initvalu_mem = EQUATIONS * sizeof(fp);
    fp *d_initvalu;
    d_initvalu = (fp *)malloc(d_initvalu_mem);

    int d_finavalu_mem;
    d_finavalu_mem = EQUATIONS * sizeof(fp);
    fp *d_finavalu;
    d_finavalu = (fp *)malloc(d_finavalu_mem);

    int d_params_mem;
    d_params_mem = PARAMETERS * sizeof(fp);
    fp *d_params;
    d_params = (fp *)malloc(d_params_mem);

    int d_com_mem;
    d_com_mem = 3 * sizeof(fp);
    fp *d_com;
    d_com = (fp *)malloc(d_com_mem);

    time1 = 0;
    time2 = 0;

    int status;

    for (i = 0; i < workload; i++) {

        status = solver(y[i],
                        x[i],
                        xmax,
                        params[i],
                        com,
                        d_initvalu,
                        d_finavalu,
                        d_params,
                        d_com);

        if (0 != status) {
            printf("STATUS: %d\n", status);
        }
    }

    time3 = 0;

    free(d_initvalu);
    free(d_finavalu);
    free(d_params);
    free(d_com);

    time4 = 0;

    printf("Time spent in different stages of the application:\n");
    printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time4 - time0) * 100);

    printf("\tGPU: COMPUTATION Components:\n");
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", (float)(timecopyin) / 1000000, (float)(timecopyin) / (float)(time4 - time0) * 100);
    printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(timekernel) / 1000000, (float)(timekernel) / (float)(time4 - time0) * 100);
    printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", (float)(timecopyout) / 1000000, (float)(timecopyout) / (float)(time4 - time0) * 100);
    timeother = time3 - time2 - timecopyin - timekernel - timecopyout;
    printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", (float)(timeother) / 1000000, (float)(timeother) / (float)(time4 - time0) * 100);

    printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time4 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4 - time0) / 1000000);

    return 0;
}

int isInteger(char *str) {
    if (*str == '\0') {
        return 0;
    }
    for (; *str != '\0'; str++) {
        if (*str < 48 || *str > 57) {
            return 0;
        }
    }
    return 1;
}

void read_file(char *filename,
               fp *input,
               int data_rows,
               int data_cols,
               int major) {
    FILE *fid;
    int i, j;
    fp temp;

    fid = fopen(filename, "r");
    if (fid == NULL) {
        printf("The file was not opened for reading\n");
        fflush(stdout);
        return;
    }

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%f", &temp);
                input[i * data_cols + j] = (fp)temp;
            }
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%f", &temp);
                input[j * data_rows + i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

int main(int argc,
         char *argv[]) {

    int cur_arg;
    int xmax;
    int workload = 1;
    char *data_dir = "."; 

    if (argc > 3) {
        for (cur_arg = 1; cur_arg < argc; cur_arg++) {

            if (strcmp(argv[cur_arg], "-time") == 0) {

                if (argc >= cur_arg + 1) {

                    if (isInteger(argv[cur_arg + 1]) == 1) {
                        xmax = atoi(argv[cur_arg + 1]);
                        if (xmax < 0) {
                            printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
                            return 0;
                        }
                        cur_arg += 1;
                    } else {
                        printf("ERROR: Value to -time argument in not a number\n");
                        return 0;
                    }
                } else {
                    printf("ERROR: Missing value to -time argument\n");
                    return 0;
                }
            } else if (strcmp(argv[cur_arg], "-p") == 0) {
                if (argc >= cur_arg + 1)
                    if (isInteger(argv[cur_arg + 1]) == 1) {
                        cur_arg = cur_arg + 1;
                    }
            } else if (strcmp(argv[cur_arg], "-d") == 0) {
                if (argc >= cur_arg + 1)
                    if (isInteger(argv[cur_arg + 1]) == 1) {
                        cur_arg = cur_arg + 1;
                    }
            } else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (argc >= cur_arg + 1) {
                    data_dir = argv[cur_arg + 1];
                    cur_arg++;
                }
            } else {
                printf("ERROR: Unknown argument\n");
                return 0;
            }
        }
    } else {
        printf("Provide time argument, example: -time 100");
        return 0;
    }

    if (workload == 1) {

        int i, j;

        long long memory;
        memory = workload * (xmax + 1) * EQUATIONS * 4;
        if (memory > 1000000000) {
            printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
            return 0;
        }

        fp ***y;
        y = (fp **)malloc(workload * sizeof(fp **));
        for (i = 0; i < workload; i++) {
            y[i] = (fp **)malloc((1 + xmax) * sizeof(fp *));
            for (j = 0; j < (1 + xmax); j++) {
                y[i][j] = (fp *)malloc(EQUATIONS * sizeof(fp));
            }
        }

        fp **x;
        x = (fp **)malloc(workload * sizeof(fp *));
        for (i = 0; i < workload; i++) {
            x[i] = (fp *)malloc((1 + xmax) * sizeof(fp));
        }

        fp **params;
        params = (fp **)malloc(workload * sizeof(fp *));
        for (i = 0; i < workload; i++) {
            params[i] = (fp *)malloc(PARAMETERS * sizeof(fp));
        }

        fp *com;
        com = (fp *)malloc(3 * sizeof(fp));

        char y_file[100];
        sprintf(y_file, "%s/%s", data_dir, "y.txt");
        for (i = 0; i < workload; i++) {
            read_file(y_file,
                      y[i][0],
                      EQUATIONS,
                      1,
                      0);
        }

        char params_file[100];
        sprintf(params_file, "%s/%s", data_dir, "params.txt");
        for (i = 0; i < workload; i++) {
            read_file(params_file,
                      params[i],
                      PARAMETERS,
                      1,
                      0);
        }

        kernel_gpu_opencl_wrapper(xmax,
                                  workload,
                                  y,
                                  x,
                                  params,
                                  com);

        FILE *pFile;
        pFile = fopen("output.txt", "w");
        if (pFile == NULL) {
            fputs("fopen example", stdout);
            return -1;
        }

        int k;
        for (i = 0; i < workload; i++) {
            fprintf(pFile, "WORKLOAD %d:\n", i);
            for (j = 0; j < (xmax + 1); j++) {
                fprintf(pFile, "\tTIME %d:\n", j);
                for (k = 0; k < EQUATIONS; k++) {
                    fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
                }
            }
        }

        fclose(pFile);

        for (i = 0; i < workload; i++) {
            for (j = 0; j < (1 + xmax); j++) {
                free(y[i][j]);
            }
            free(y[i]);
        }
        free(y);

        for (i = 0; i < workload; i++) {
            free(x[i]);
        }
        free(x);

        for (i = 0; i < workload; i++) {
            free(params[i]);
        }
        free(params);

        free(com);
    }

    return 0;
}

