#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define REC_LENGTH 49
#define MAX_RECORDS 2000000

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

char *data_folder = NULL;

void findLowest(Record *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[256], db_fullname[512];
    int recNum = 0;

    if (data_folder == NULL) {
        data_folder = getenv("DATA_FOLDER");
        if (data_folder == NULL) {
            data_folder = ".";
        }
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        return 0;
    }

    while (!feof(flist) && recNum < maxRecords) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            break;
        }
        // Remove potential trailing newline or whitespace from dbname if fscanf didn't handle it perfectly
        dbname[strcspn(dbname, "\n\r")] = 0;

        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            fprintf(stderr, "error opening a db (%s)\n", db_fullname);
            fclose(flist);
            return recNum;
        }

        while (!feof(fp) && recNum < maxRecords) {
            Record record;
            LatLong latLong;

            // Read line
            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            // Check if line is valid (contains data)
            if (strlen(record.recString) < 38) { 
                // Ensure we have enough chars for the substrings we extract later
                continue; 
            }

            char substr[6];

            // Extract latitude (chars 28-32)
            for(i=0; i<5; i++) {
                if (28+i < strlen(record.recString))
                    substr[i] = record.recString[28+i];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Extract longitude (chars 33-37)
            for(i=0; i<5; i++) {
                if (33+i < strlen(record.recString))
                    substr[i] = record.recString[33+i];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 256);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (i+1 < argc) {
                        if (argv[i][2] == 'a') {
                            *lat = atof(argv[i + 1]);
                        } else {
                            *lng = atof(argv[i + 1]);
                        }
                        i++;
                    }
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
