#define REC_LENGTH 49

static char *data_folder = NULL;

void findLowest(Record *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

void compute_distances(LatLong *locations, float *distances, int numRecords, float lat, float lng) {
    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        float diff_lat = lat - locations[i].lat;
        float diff_lng = lng - locations[i].lng;
        distances[i] = (float)sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    LatLong *locations,
    float lat,
    float lng,
    int timing) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    double start_time = 0.0, end_time = 0.0;
    if (timing) {
        start_time = omp_get_wtime();
    }

    compute_distances(locations, distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
        printf("Kernel execution time: %f seconds\n", end_time - start_time);
    }

    return distances;
}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    // Use the global data_folder set by parseCommandline
    const char *folder = data_folder ? data_folder : ".";

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist) && recNum < maxRecords) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            break;
        }
        sprintf(db_fullname, "%s/%s", folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp) && recNum < maxRecords) {
            Record record;
            LatLong latLong;
            if (fgets(record.recString, 49, fp) == NULL) break;

            // Remove newline if present
            size_t len = strlen(record.recString);
            if (len > 0 && record.recString[len-1] == '\n') {
                record.recString[len-1] = '\0';
                len--;
            }

            char substr[6];
            for (i = 0; i < 5; i++) {
                if (28 + i < len) substr[i] = record.recString[28 + i];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) {
                if (33 + i < len) substr[i] = record.recString[33 + i];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

