int main(int argc, char *argv[]) {
    Record *records;
    LatLong *locations;
    float *recordDistances;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;
    int numRecords;
    int i;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int maxRecords = 1000000; 
    records = (Record *)malloc(sizeof(Record) * maxRecords);
    locations = (LatLong *)malloc(sizeof(LatLong) * maxRecords);

    if (!records || !locations) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    numRecords = loadData(filename, records, locations, maxRecords);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    double total_start = 0.0, total_end = 0.0;
    if (timing) {
        total_start = omp_get_wtime();
    }

    recordDistances = OpenMPFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
