float *OpenMPFindNearestNeighbors(
    int numRecords,
    LatLongVector *locations,
    float lat,
    float lng,
    int timing) {

    LatLong *d_locations = locations->data;
    float *d_distances = (float *)malloc(sizeof(float) * numRecords);

    if (!d_distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(-1);
    }

    double start_time = 0.0, end_time = 0.0;
    if (timing) {
        start_time = omp_get_wtime();
    }

    // Execute kernel
    nearest_neighbor_kernel(d_locations, d_distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
    }

    if (timing) {
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t%f [%.2fMB]\t%f\t%f [%.2fMB]\t%f\n\n", 
               numRecords, 
               0.0, (float)((sizeof(LatLong) * numRecords)/1e6),
               end_time - start_time,
               0.0, (float)((sizeof(float) * numRecords)/1e6),
               end_time - start_time);

        printf("Init: 0.000000\n");
        printf("MemAlloc: 0.000000\n");
        printf("HtoD: 0.000000\n");
        printf("Exec: %f\n", (end_time - start_time) * 1000.0);
        printf("DtoH: 0.000000\n");
        printf("Close: 0.000000\n");
        printf("Total: %f\n", (end_time - start_time) * 1000.0);
    }

    return d_distances;
}

