#define SCORE(i, j) input_itemsets_l[j + i * (BLOCK_SIZE+1)]
#define REF(i, j)   reference_l[j + i * BLOCK_SIZE]

void nw_kernel1(
		   int  * reference_d, 
		   int  * input_itemsets_d, 
		   int  * output_itemsets_d, 
		   int  * input_itemsets_l,
		   int  * reference_l,
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c
    )
{  

    int bx = 0; // In OpenMP, we iterate over blocks in the outer loop, so bx is effectively 0 relative to the chunk being processed by this thread instance if we were mapping 1:1. 
    // However, the original code uses get_group_id(0) which corresponds to the block index in the queue.
    // In the OpenMP translation, the outer loop iterates 'blk'. 
    // The original kernel was called with global_work = BLOCK_SIZE * blk, local_work = BLOCK_SIZE.
    // This means there were 'blk' groups. The kernel logic depends on bx (group id).
    // To replicate the behavior exactly, we must loop over the groups (bx) that were active in that invocation.
    // The original invocation for step 'blk' ran groups 0 to blk-1.

    // We will restructure: The outer loop in main calls this function for each 'blk'.
    // Inside this function, we must simulate the execution of all groups (bx) from 0 to blk-1.
    // Since OpenMP threads are independent, we can parallelize over bx.

    #pragma omp parallel for
    for (int bx = 0; bx < blk; bx++) {

    int tx;
    // We need a local buffer for each thread/group combination. 
    // Since we are parallelizing over bx, each thread handles one bx.
    // We allocate local arrays on stack.
    int input_itemsets_l_local[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int reference_l_local[BLOCK_SIZE*BLOCK_SIZE];

    // Map pointers
    int *input_itemsets_l = input_itemsets_l_local;
    int *reference_l = reference_l_local;

    // Simulate local id loop. Since we are one group, we must iterate tx from 0 to BLOCK_SIZE-1
    // But the algorithm relies on synchronization between tx. 
    // In OpenMP, we can't easily simulate barrier within a group if we parallelize over groups.
    // However, the original code has 1D block of size BLOCK_SIZE.
    // So for a specific bx, we have BLOCK_SIZE threads.
    // We must serialize the tx loop for a given bx to maintain barriers, OR use OpenMP barriers if we structure it as a team.
    // Given the complex barrier usage, it is safest to run the tx loop sequentially for each bx, 
    // OR if we want parallelism, we need to map the team to bx and then loop tx.
    // But standard OpenMP parallel for splits the loop. 
    // Let's try to parallelize over bx, and inside, run tx sequentially? That loses performance.
    // Better approach: Parallelize over bx, and inside use a single thread to run the tx loop? No.
    // The original code: N groups, M threads per group.
    // Total work = N * M.
    // We can parallelize over (bx, tx) combined index? 
    // But barriers are per group (bx).
    // So we must group threads by bx.
    // This is hard in standard OpenMP without nested parallelism or specific team handling.
    // Alternative: The outer loop in main iterates blk. The number of groups is 'blk'.
    // We can just run a loop for bx from 0 to blk-1. Inside, we run tx from 0 to BLOCK_SIZE-1.
    // To parallelize, we can treat (bx * BLOCK_SIZE + tx) as the linear thread index?
    // No, barriers are required within bx.
    // Strategy: Use #pragma omp parallel for for bx. Inside, use a single thread to execute the tx logic? 
    // No, that defeats parallelism.
    // Correct Strategy: The original code executes 'blk' groups simultaneously.
    // We can use OpenMP to parallelize the 'bx' loop. Inside each 'bx', we have a sequence of operations for 'tx' that require synchronization.
    // Since the operations for different 'tx' within a 'bx' are tightly coupled with barriers, we should probably execute the 'tx' loop sequentially for each 'bx' if we parallelize over 'bx'.
    // BUT, wait. The original kernel runs ALL groups (bx) in parallel. And within a group, threads (tx) run in parallel with barriers.
    // If we parallelize over bx, we have one thread (or team) per bx.
    // If we assign one CPU thread to one bx, then inside that CPU thread, we must simulate the tx parallelism? 
    // Or we just run the tx loop sequentially? 
    // The algorithm is a wavefront. The barriers ensure that step m is done by all tx before step m+1.
    // If we run tx sequentially, the logic holds (barriers are implicit in sequential execution).
    // So: Parallelize over bx. Inside, loop tx sequentially. This preserves correctness and utilizes multiple cores for different blocks.

    // Re-reading the code: The kernel is invoked with global_work = BLOCK_SIZE * blk.
    // This means there are 'blk' groups. 
    // So for a fixed 'blk' argument passed to this function, we must process groups 0..blk-1.

    // Let's assume we are running this function in a context where we want to parallelize the groups.

    // However, the provided main loop structure in the original code:
    // for( int blk = 1 ; blk <= worksize/BLOCK_SIZE ; blk++){
    //   global_work[0] = BLOCK_SIZE * blk;
    //   ...
    //   clEnqueueNDRangeKernel(..., global_work, local_work, ...)
    // }
    // This means at step 'blk', we run 'blk' groups.
    // So in OpenMP, for a fixed 'blk', we parallelize over bx from 0 to blk-1.

    // Inside the bx loop:
    int base = offset_r * cols + offset_c;
    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    int index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
    int index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
    int index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
    int index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    // We must iterate tx from 0 to BLOCK_SIZE-1. 
    // Since we need barriers, and we are running sequentially for tx in this implementation (to avoid complex thread grouping),
    // we just loop tx.

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        // Compute indices for this tx
        int cur_index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
        int cur_index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
        int cur_index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
        int cur_index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        if (tx == 0){
            SCORE(tx, 0) = input_itemsets_d[cur_index_nw + tx];
        }
        // Barrier simulated by sequential execution
    }

    // Next section: load REF
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
        for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
            REF(ty, tx) =  reference_d[cur_index + cols * ty];
    }

    // Next: SCORE((tx + 1), 0)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
        SCORE((tx + 1), 0) = input_itemsets_d[cur_index_w + cols * tx];
    }

    // Next: SCORE(0, (tx + 1))
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
        SCORE(0, (tx + 1)) = input_itemsets_d[cur_index_n];
    }

    // Main computation loops
    for( int m = 0 ; m < BLOCK_SIZE ; m++){
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if ( tx <= m ){
                int t_index_x =  tx + 1;
                int t_index_y =  m - tx + 1;
                SCORE(t_index_y, t_index_x) = maximum( SCORE((t_index_y-1), (t_index_x-1)) + REF((t_index_y-1), (t_index_x-1)),
                                                       SCORE((t_index_y),   (t_index_x-1)) - (penalty), 
                                                       SCORE((t_index_y-1), (t_index_x))   - (penalty));
            }
        }
    }

    for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if ( tx <= m){
                int t_index_x =  tx + BLOCK_SIZE - m ;
                int t_index_y =  BLOCK_SIZE - tx;
                SCORE(t_index_y, t_index_x) = maximum(  SCORE((t_index_y-1), (t_index_x-1)) + REF((t_index_y-1), (t_index_x-1)),
                                                        SCORE((t_index_y),   (t_index_x-1)) - (penalty), 
                                                        SCORE((t_index_y-1), (t_index_x))   - (penalty));
            }
        }
    }

    // Write back
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
        for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
            input_itemsets_d[cur_index + cols * ty] = SCORE((ty+1), (tx+1));
    }

    } // end bx loop
}

void nw_kernel2(
		   int  * reference_d, 
		   int  * input_itemsets_d, 
		   int  * output_itemsets_d, 
		   int  * input_itemsets_l,
		   int  * reference_l,
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c
    )
{  
    #pragma omp parallel for
    for (int bx = 0; bx < blk; bx++) {

    int tx;
    int input_itemsets_l_local[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int reference_l_local[BLOCK_SIZE*BLOCK_SIZE];
    int *input_itemsets_l = input_itemsets_l_local;
    int *reference_l = reference_l_local;

    int base = offset_r * cols + offset_c;
    int b_index_x = bx + block_width - blk;
    int b_index_y = block_width - bx -1;

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
        if (tx == 0)
            SCORE(tx, 0) = input_itemsets_d[cur_index_nw];
    }

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
        for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
            REF(ty, tx) =  reference_d[cur_index + cols * ty];
    }

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
        SCORE((tx + 1), 0) = input_itemsets_d[cur_index_w + cols * tx];
    }

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
        SCORE(0, (tx + 1)) = input_itemsets_d[cur_index_n];
    }

    for( int m = 0 ; m < BLOCK_SIZE ; m++){
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if ( tx <= m ){
                int t_index_x =  tx + 1;
                int t_index_y =  m - tx + 1;
                SCORE(t_index_y, t_index_x) = maximum(  SCORE((t_index_y-1), (t_index_x-1)) + REF((t_index_y-1), (t_index_x-1)),
                                                        SCORE((t_index_y),   (t_index_x-1)) - (penalty), 
                                                        SCORE((t_index_y-1), (t_index_x))   - (penalty));
            }
        }
    }

    for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if ( tx <= m){
                int t_index_x =  tx + BLOCK_SIZE - m ;
                int t_index_y =  BLOCK_SIZE - tx;
                SCORE(t_index_y, t_index_x) = maximum( SCORE((t_index_y-1), (t_index_x-1)) + REF((t_index_y-1), (t_index_x-1)),
                                                       SCORE((t_index_y),   (t_index_x-1)) - (penalty), 
                                                       SCORE((t_index_y-1), (t_index_x))   - (penalty));
            }
        }
    }

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int cur_index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
        for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
            input_itemsets_d[cur_index + ty * cols] = SCORE((ty+1), (tx+1));
    }
    }
}

