int maximum( int a, int b, int c){
	int k;
	if( a <= b )
		k = b;
	else 
		k = a;

	if( k <=c )
		return(c);
	else
		return(k);
}

void nw_kernel1( int  * reference_d, 
		   int  * input_itemsets_d, 
		   int  * output_itemsets_d, 
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c
    )
{  
    // Simulating one block execution per thread in OpenMP parallel region
    // bx corresponds to the thread index within the block logic, but since OpenMP threads execute independently,
    // we must iterate over all 'bx' (threads) that would have been in the OpenCL group.
    // However, the original code structure implies one kernel launch processes one diagonal block step.
    // In OpenCL, get_group_id(0) was bx. The loop in main launches kernel with global_work = BLOCK_SIZE * blk.
    // This means for a specific 'blk', there are 'blk' groups? No, global_work = BLOCK_SIZE * blk means total threads = BLOCK_SIZE * blk.
    // Wait, the OpenCL code: global_work[0] = BLOCK_SIZE * blk; local_work[0] = BLOCK_SIZE;
    // This creates 'blk' groups. Each group has BLOCK_SIZE threads.
    // Inside the kernel, bx = get_group_id(0). So bx ranges from 0 to blk-1.
    // The algorithm seems to process a diagonal of blocks.
    // To translate this to OpenMP, we need to replicate the logic for each group (bx) that was active.

    // We will use a parallel loop over bx from 0 to blk-1.

    int local_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int local_reference_l[BLOCK_SIZE*BLOCK_SIZE];

    #pragma omp parallel for
    for(int bx = 0; bx < blk; bx++) {

        int tx = 0; // In OpenCL, tx varies 0..BLOCK_SIZE-1. But the logic inside uses tx heavily.
        // Actually, the OpenCL kernel runs BLOCK_SIZE threads per group.
        // Each thread (tx) does specific work.
        // To simulate this in OpenMP, we need a loop over tx as well, or restructure.
        // Given the heavy use of barriers and shared local memory (input_itemsets_l, reference_l) 
        // where threads cooperate, the most direct translation is to have each OpenMP thread 
        // simulate one OpenCL thread (tx) within a specific group (bx).
        // But OpenMP threads don't share L1 cache automatically as __local memory with barriers in the same way.
        // We must use explicit arrays and omp barrier.

        // However, the outer loop in main calls the kernel multiple times with increasing blk.
        // Let's re-read the main loop:
        // for( int blk = 1 ; blk <= worksize/BLOCK_SIZE ; blk++){
        //   global_work[0] = BLOCK_SIZE * blk;
        //   clEnqueueNDRangeKernel(..., kernel1, ...)
        // }
        // This means for step 'blk', we launch 'blk' groups of 'BLOCK_SIZE' threads.
        // Total threads = blk * BLOCK_SIZE.
        // Each group (bx) processes a specific block on the diagonal.
        // Inside the group, threads (tx) cooperate using local memory.

        // To translate to OpenMP:
        // We can create a parallel region where each thread handles one (bx, tx) pair?
        // Or, since the groups are independent, we can parallelize over bx, and inside, simulate the tx loop?
        // No, the cooperation within a group (barriers) requires simulating the threads.
        // Since BLOCK_SIZE is small (16), we can just loop over tx inside the bx loop, using a single thread to simulate the group?
        // NO, the original code relies on parallel execution of tx within a group for performance (though logically sequential due to barriers).
        // Actually, looking at the code:
        // if (tx == 0) ...
        // for ty ... REF(ty, tx) = ... (each tx writes a column)
        // SCORE((tx+1), 0) = ... (each tx writes one)
        // Then the main loop:
        // for m ... if (tx <= m) ... (wavefront)
        // This is a classic parallel DP wavefront within a block.
        // To preserve the algorithm exactly, we should simulate the threads.
        // But OpenMP doesn't have "groups" of threads with local memory easily without nested parallelism or manual simulation.
        // Given the constraints and the fact that BLOCK_SIZE is small, we can simulate the group by having one OpenMP thread run all tx steps sequentially?
        // That would change the performance profile but preserve the logic if we remove barriers.
        // BUT the barriers ensure ordering. If we run sequentially, barriers are implicit.
        // Let's try to map: OpenMP thread -> OpenCL Group (bx). Inside, we loop tx from 0 to BLOCK_SIZE-1 sequentially.
        // This removes the intra-block parallelism but preserves the inter-block parallelism (over bx) and the correctness.
        // Is intra-block parallelism required for correctness? No, barriers enforce order. Sequential execution of tx satisfies barriers.
        // So: Parallelize over bx. Sequential loop over tx. Use a local array for each bx.

        int * input_itemsets_l = local_input_itemsets_l; // Pointer to local buffer for this bx
        int * reference_l = local_reference_l;           // Pointer to local buffer for this bx

        // However, declaring large arrays inside a parallel loop might be inefficient or cause stack issues.
        // Let's allocate them dynamically or use a fixed size if BLOCK_SIZE is known.
        // Since BLOCK_SIZE is macro, we can use static arrays inside the loop (stack) as size is small (17*17 ints).

        // Re-declare inside to ensure per-thread (per-bx) storage
        int l_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
        int l_reference_l[BLOCK_SIZE*BLOCK_SIZE];

        // Now simulate the threads tx=0..BLOCK_SIZE-1 sequentially
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {

            int base = offset_r * cols + offset_c;
            int b_index_x = bx;
            int b_index_y = blk - 1 - bx;

            int index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
            int index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            int index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
            int index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            // Simulate tx=0 work
            if (tx == 0){
                l_input_itemsets_l[0 + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_nw + 0];
            }
            // Barrier: implicit since sequential

            // Simulate work for current tx
            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                l_reference_l[ty + tx * BLOCK_SIZE] =  reference_d[index + cols * ty];

            // Barrier

            l_input_itemsets_l[(tx + 1) + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_w + cols * tx];

            // Barrier

            l_input_itemsets_l[0 + (tx + 1) * (BLOCK_SIZE+1)] = input_itemsets_d[index_n];

            // Barrier

            // Main DP loops
            for( int m = 0 ; m < BLOCK_SIZE ; m++){
                if ( tx <= m ){
                    int t_index_x =  tx + 1;
                    int t_index_y =  m - tx + 1;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
                // Barrier: implicit
            }

            // Barrier

            for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
                if ( tx <= m){
                    int t_index_x =  tx + BLOCK_SIZE - m ;
                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
                // Barrier: implicit
            }

            // Barrier

            // Write back only for the simulated tx? 
            // In OpenCL, all threads write.
            // Here we are looping tx, so we write for each tx.
            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets_d[index + cols * ty] = l_input_itemsets_l[(ty+1) + (tx+1)*(BLOCK_SIZE+1)];
        }
    }
}

void nw_kernel2( int  * reference_d, 
		   int  * input_itemsets_d, 
		   int  * output_itemsets_d, 
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c
    )
{  
    int local_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int local_reference_l[BLOCK_SIZE*BLOCK_SIZE];

    #pragma omp parallel for
    for(int bx = 0; bx < blk; bx++) {

        int l_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
        int l_reference_l[BLOCK_SIZE*BLOCK_SIZE];

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {

            int base = offset_r * cols + offset_c;
            int b_index_x = bx + block_width - blk;
            int b_index_y = block_width - bx -1;

            int index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
            int index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            int index_w   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
            int index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            if (tx == 0)
                l_input_itemsets_l[0 + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_nw];

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                l_reference_l[ty + tx * BLOCK_SIZE] =  reference_d[index + cols * ty];

            // barrier

            l_input_itemsets_l[(tx + 1) + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_w + cols * tx];

            // barrier

            l_input_itemsets_l[0 + (tx + 1) * (BLOCK_SIZE+1)] = input_itemsets_d[index_n];

            // barrier

            for( int m = 0 ; m < BLOCK_SIZE ; m++){
                if ( tx <= m ){
                    int t_index_x =  tx + 1;
                    int t_index_y =  m - tx + 1;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
            }

            for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
                if ( tx <= m){
                    int t_index_x =  tx + BLOCK_SIZE - m ;
                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
            }

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets_d[index + ty * cols] = l_input_itemsets_l[(ty+1) + (tx+1)*(BLOCK_SIZE+1)];
        }
    }
}

