#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulated buffers
    int* d_gpuWall = new int[size - cols];
    int* d_gpuResult[2];
    d_gpuResult[0] = new int[cols];
    d_gpuResult[1] = new int[cols];
    int* d_outputBuffer = new int[16384];

    // Copy initial data
    for(int i=0; i<size-cols; ++i) d_gpuWall[i] = my_data[i+cols];
    for(int i=0; i<cols; ++i) d_gpuResult[0][i] = my_data[i];
    for(int i=0; i<cols; ++i) d_gpuResult[1][i] = 0;
    for(int i=0; i<16384; ++i) d_outputBuffer[i] = h_outputBuffer[i];

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int src = 1, final_ret = 0;

    // Determine number of blocks needed
    int small_block_cols_base = BLOCK_SIZE - (pyramid_height*HALO*2);
    if (small_block_cols_base <= 0) small_block_cols_base = 1; 
    int num_blocks = (cols + 2*borderCols + small_block_cols_base - 1) / small_block_cols_base;

    // Allocate local buffers for each block
    int* all_prev = new int[num_blocks * BLOCK_SIZE];
    int* all_result = new int[num_blocks * BLOCK_SIZE];

    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows-t-1);
        int theHalo = HALO;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        #pragma omp parallel for
        for (int bx = 0; bx < num_blocks; bx++) {
            int* local_prev = all_prev + bx * BLOCK_SIZE;
            int* local_result = all_result + bx * BLOCK_SIZE;

            dynproc_kernel (arg0,
                          d_gpuWall,
                          d_gpuResult[src],
                          d_gpuResult[final_ret],
                          cols,
                          rows,
                          t,
                          borderCols,
                          theHalo,
                          local_prev,
                          local_result,
                          d_outputBuffer,
                          bx);
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    // Copy result back
    for(int i=0; i<cols; ++i) result[i] = d_gpuResult[final_ret][i];
    for(int i=0; i<16384; ++i) h_outputBuffer[i] = d_outputBuffer[i];

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", my_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    delete[] d_gpuWall;
    delete[] d_gpuResult[0];
    delete[] d_gpuResult[1];
    delete[] d_outputBuffer;
    delete[] all_prev;
    delete[] all_result;

#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    delete[] my_data;
    delete[] wall;
    delete[] result;
    free(h_outputBuffer);

    return EXIT_SUCCESS;
}

