// Helper function to simulate the kernel logic for a single block
void dynproc_kernel_block(int iteration,
                          int* gpuWall,
                          int* gpuSrc,
                          int* gpuResults,
                          int cols,
                          int rows,
                          int startStep,
                          int border,
                          int HALO,
                          int BLOCK_SIZE,
                          int bx,
                          int* outputBuffer)
{
    // Simulate local memory
    int* prev = new int[BLOCK_SIZE];
    int* result_arr = new int[BLOCK_SIZE];

    int tx; // Thread index within block

    // We must iterate sequentially for threads within a block to simulate barrier behavior
    // However, to preserve parallelism across blocks, this function is called per block.
    // Inside this function, we simulate the threads sequentially to maintain dependency order 
    // exactly as the OpenCL kernel does with barriers.

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
        int blkX = (small_block_cols*bx) - border;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int xidx = blkX+tx;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        if(IN_RANGE(xidx, 0, cols-1))
        {
            prev[tx] = gpuSrc[xidx];
        }

        // Barrier simulated by sequential execution within this loop context
    }

    bool computed = false;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        // Simulate parallel threads step
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
            int blkX = (small_block_cols*bx) - border;
            int blkXmax = blkX+BLOCK_SIZE-1;
            int xidx = blkX+tx;
            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
            int W = tx-1; int E = tx+1;
            W = (W < validXmin) ? validXmin : W;
            E = (E > validXmax) ? validXmax : E;
            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
            {
                computed = true;
                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                result_arr[tx] = shortest + gpuWall[index];

                if (tx==11 && i==0)
                {
                    int bufIndex = gpuSrc[xidx];
                    if (bufIndex >= 0 && bufIndex < 16384) {
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }
        }
        // Barrier

        if(i==iteration-1)
        {
            break;
        }

        // Update prev
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
            int blkX = (small_block_cols*bx) - border;
            int blkXmax = blkX+BLOCK_SIZE-1;
            int xidx = blkX+tx;
            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            // Re-calculate computed status for this thread based on logic above
            bool thread_computed = false;
            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid ) {
                thread_computed = true;
            }

            if(thread_computed)
            {
                prev[tx] = result_arr[tx];
            }
        }
        // Barrier
    }

    // Write results
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);
        int blkX = (small_block_cols*bx) - border;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int xidx = blkX+tx;
        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        bool thread_computed = false;
        // Check last iteration condition roughly, or just rely on result validity
        // The original code sets computed flag in the loop. 
        // We need to know if the last iteration computed this thread.
        // Simplified: if xidx is valid and within range for last iter
        int i = iteration - 1;
        if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid ) {
            thread_computed = true;
        }

        if (thread_computed && IN_RANGE(xidx, 0, cols-1))
        {
            gpuResults[xidx] = result_arr[tx];
        }
    }

    delete[] prev;
    delete[] result_arr;
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int size = rows * cols;

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

