        // Loop 1: src=0, final_ret=1. (Read 0, Write 1)
        // Loop 2: src=1, final_ret=0. (Read 1, Write 0)
        // Our variables: current_src, current_dest.
        // Initially current_src = d_gpuResult0 (index 0), current_dest = d_gpuResult1 (index 1).
        // This matches Loop 1 (Read 0, Write 1).
        // Next iteration we swap.

        int num_blocks = (cols + borderCols) / (BLOCK_SIZE - 2*iteration*HALO) + 2; 
        // Estimate enough blocks to cover the range. 
        // Or simply iterate while the start of the block is less than cols + border.

        #pragma omp parallel for schedule(static)
        for (int bx = 0; bx < num_blocks; bx++)
        {
            dynproc_kernel_block(iteration,
                                 gpuWall,
                                 current_src,
                                 current_dest,
                                 cols,
                                 rows,
                                 startStep,
                                 borderCols,
                                 theHalo,
                                 BLOCK_SIZE,
                                 bx,
                                 h_outputBuffer);
        }

        // Swap buffers
        int* temp = current_src;
        current_src = current_dest;
        current_dest = temp;
    }

    // Result is in current_src because we swapped at end of loop?
    // Loop 1: Read 0, Write 1. Swap: src=1, dest=0.
    // Loop ends. Result is in 'dest' before swap? No.
    // OpenCL: writes to d_gpuResult[final_ret].
    // Then reads d_gpuResult[final_ret].
    // In our simulation:
    // Iter 1: writes to current_dest (1). Then swap: current_src becomes 1.
    // Iter 2: reads current_src (1), writes to current_dest (0). Swap: current_src becomes 0.
    // So after loop, current_src holds the latest result.

    for(int i=0; i<cols; i++) {
        result[i] = current_src[i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", my_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    delete[] my_data;
    delete[] wall;
    delete[] result;
    delete[] d_gpuResult0;
    delete[] d_gpuResult1;
    free(h_outputBuffer);

    return 0;
}

