// Helper function to simulate the kernel logic for a single block
void dynproc_kernel_sim(int iteration,
                        int* gpuWall,
                        int* gpuSrc,
                        int* gpuResults,
                        int cols,
                        int rows,
                        int startStep,
                        int border,
                        int HALO_val,
                        int BLOCK_SIZE,
                        int bx,
                        int* outputBuffer)
{
    // Allocate local memory (prev and result) for this block
    int* prev = new int[BLOCK_SIZE];
    int* result_arr = new int[BLOCK_SIZE];

    int tx; 

    // Simulate parallel threads within the block
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int small_block_cols = BLOCK_SIZE - (iteration*HALO_val*2);
        int blkX = (small_block_cols*bx) - border;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int xidx = blkX+tx;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        if(IN_RANGE(xidx, 0, cols-1))
        {
            prev[tx] = gpuSrc[xidx];
        } else {
            prev[tx] = 0; 
        }
        result_arr[tx] = 0;
    }

    for (int i = 0; i < iteration; i++)
    {
        #pragma omp parallel for
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            int small_block_cols = BLOCK_SIZE - (iteration*HALO_val*2);
            int blkX = (small_block_cols*bx) - border;
            int blkXmax = blkX+BLOCK_SIZE-1;
            int xidx = blkX+tx;
            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);
            bool computed = false;

            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
            {
                computed = true;
                int W = tx-1;
                int E = tx+1;
                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;

                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                if (index >= 0 && index < (rows-1)*cols) { 
                    result_arr[tx] = shortest + gpuWall[index];
                }

                if (tx==11 && i==0)
                {
                    int bufIndex = gpuSrc[xidx];
                    if (IN_RANGE(bufIndex, 0, 16383)) {
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }

            if(computed)
            {
                prev[tx] = result_arr[tx];
            }
        }
        if(i==iteration-1) break; 
    }

    // Write results
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int small_block_cols = BLOCK_SIZE - (iteration*HALO_val*2);
        int blkX = (small_block_cols*bx) - border;
        int xidx = blkX+tx;

        int i = iteration - 1;
        int validXmin = (blkX < 0) ? -blkX : 0;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        bool computed = false;
        if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
        {
            computed = true;
        }

        if (computed && IN_RANGE(xidx, 0, cols-1))
        {
            gpuResults[xidx] = result_arr[tx];
        }
    }

    delete[] prev;
    delete[] result_arr;
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;

    int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulate GPU Wall buffer (excluding first row)
    int* d_gpuWall = new int[size - cols];
    for(int i=0; i<size-cols; ++i) {
        d_gpuWall[i] = my_data[i+cols];
    }

    int* d_gpuResult[2];
    d_gpuResult[0] = new int[cols];
    d_gpuResult[1] = new int[cols];

    // Initialize d_gpuResult[0] with first row of data
    for(int i=0; i<cols; ++i) {
        d_gpuResult[0][i] = my_data[i];
    }

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int BLOCK_SIZE = 256;
    if (cols < BLOCK_SIZE) BLOCK_SIZE = cols;

    int num_blocks = (rows * cols) / BLOCK_SIZE;
    if ((rows * cols) % BLOCK_SIZE != 0) num_blocks++;

    int src = 1, final_ret = 0;

    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows-t-1);
        int theHalo = HALO;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        #pragma omp parallel for
        for (int bx = 0; bx < num_blocks; bx++) {
            dynproc_kernel_sim(arg0, d_gpuWall, d_gpuResult[src], d_gpuResult[final_ret],
                               cols, rows, t, borderCols, theHalo, BLOCK_SIZE, bx, h_outputBuffer);
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    for(int i=0; i<cols; ++i) {
        result[i] = d_gpuResult[final_ret][i];
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", my_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    delete[] d_gpuWall;
    delete[] d_gpuResult[0];
    delete[] d_gpuResult[1];
    free(h_outputBuffer);

#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    delete[] my_data;
    delete[] wall;
    delete[] result;

    return EXIT_SUCCESS;
}

