// Helper functions for graphics and resize (inline from source files to avoid missing headers)
void write_graphics_local(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range){
    FILE* fid;
    int i, j;
    fid = fopen(filename, "w");
    if( fid == NULL ){
        printf( "The file was not created/opened for writing\n" );
        return;
    }
    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[i*data_cols+j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[j*data_rows+i]);
            }
            fprintf(fid, "\n");
        }
    }
    fclose(fid);
}

void read_graphics_local(char* filename, fp* input, int data_rows, int data_cols, int major){
    FILE* fid;
    int i, j;
    char c;
    int temp;
    fid = fopen(filename, "r");
    if( fid == NULL ){
        printf( "The file was not opened for reading\n" );
        return;
    }
    i = 0;
    while(i<3){
        c = fgetc(fid);
        if(c == '\n'){
            i = i+1;
        }
    };
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[i*data_cols+j] = (fp)temp;
            }
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[j*data_rows+i] = (fp)temp;
            }
        }
    }
    fclose(fid);
}

void resize_local(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major){
    int i, j;
    int i2, j2;
    if(major == 0){
        for(i=0, i2=0; i<output_rows; i++, i2++){
            if(i2>=input_rows){ i2 = i2 - input_rows; }
            for(j=0, j2=0; j<output_cols; j++, j2++){
                if(j2>=input_cols){ j2 = j2 - input_cols; }
                output[i*output_cols+j] = input[i2*input_cols+j2];
            }
        }
    } else {
        for(j=0, j2=0; j<output_cols; j++, j2++){
            if(j2>=input_cols){ j2 = j2 - input_cols; }
            for(i=0, i2=0; i<output_rows; i++, i2++){
                if(i2>=input_rows){ i2 = i2 - input_rows; }
                output[j*output_rows+i] = input[j2*input_rows+i2];
            }
        }
    }
}

// Kernel implementations translated to OpenMP

void extract_kernel(long d_Ne, fp* d_I){
    #pragma omp parallel for
    for(long ei = 0; ei < d_Ne; ei++){
        d_I[ei] = exp(d_I[ei]/255);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2){
    #pragma omp parallel for
    for(long ei = 0; ei < d_Ne; ei++){
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei]*d_I[ei];
    }
}

// Reduction logic adapted for OpenMP with manual tree reduction per block simulation
// Since OpenMP doesn't have explicit blocks/local memory in the same way, we simulate the behavior
// by processing chunks corresponding to the original block structure.
void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim){
    int num_threads = NUMBER_THREADS;
    int blocks_x = gridDim;

    // We allocate temporary storage for each block's reduction
    // In OpenMP, we can't easily share local memory between threads of a "block" without explicit arrays
    // We simulate the block reduction using a temporary array sized for max blocks * threads
    // However, to strictly follow the algorithm which reduces in-place in d_sums/d_sums2 using a tree within a block:
    // We will iterate over blocks and perform the reduction logic sequentially per block but parallelized inside if possible,
    // or simply parallelize the outer loop over blocks if the reduction logic is self-contained per block.
    // The original code runs one block per thread group.

    // To match the exact behavior of the OpenCL kernel which assumes a specific block/thread mapping:
    // We loop over blocks (bx) and inside simulate the threads (tx).
    // Since d_sums is updated in place, we must be careful. The original kernel reads from d_sums[ei*d_mul] and writes to d_sums[bx*d_mul*NUMBER_THREADS].
    // This implies a hierarchical reduction.

    // For OpenMP, we can parallelize the loop over blocks (bx), as each block writes to a distinct location in d_sums/d_sums2 
    // (index bx*d_mul*NUMBER_THREADS).

    #pragma omp parallel for
    for(int bx = 0; bx < gridDim; bx++){
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
        int df = 0;

        // Simulate threads tx from 0 to NUMBER_THREADS-1
        // Only first 'd_no' elements are valid inputs for this reduction step
        // In the original, ei = bx*NUMBER_THREADS + tx. If ei < d_no, load data.
        // Here, we just load data for tx < d_no - bx*NUMBER_THREADS? 
        // Wait, d_no is the total number of active elements across ALL blocks in this step.
        // The condition in OpenCL: if(ei < d_no) where ei = bx*NUMBER_THREADS + tx.
        // So for a given block bx, valid tx are those where bx*NUMBER_THREADS + tx < d_no.

        for(int tx = 0; tx < NUMBER_THREADS; tx++){
            long ei = (long)bx * NUMBER_THREADS + tx;
            if(ei < d_no){
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            } else {
                // Initialize to 0 to avoid affecting sum if logic falls through, though logic checks bounds
                d_psum[tx] = 0.0;
                d_psum2[tx] = 0.0;
            }
        }

        // Barrier equivalent: implicit as we are in a single thread context simulating the block now
        // But wait, we are inside a parallel for over bx. Each bx is handled by one thread (or team if nested, but let's keep simple).
        // The original code uses multiple threads (tx) within a block to do the tree reduction.
        // To preserve the algorithm exactly without nested parallelism overhead/complexity, we simulate the tx loop sequentially within the bx loop.
        // This effectively serializes the intra-block reduction but keeps inter-block parallelism.

        if(nf == NUMBER_THREADS){
            for(int i = 2; i <= NUMBER_THREADS; i = 2 * i){
                for(int tx = 0; tx < NUMBER_THREADS; tx++){
                    if((tx + 1) % i == 0){
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                    }
                }
            }
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if(bx != (gridDim - 1)){
                for(int i = 2; i <= NUMBER_THREADS; i = 2 * i){
                    for(int tx = 0; tx < NUMBER_THREADS; tx++){
                        if((tx + 1) % i == 0){
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                        }
                    }
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                // Last block with partial data
                for(int i = 2; i <= NUMBER_THREADS; i = 2 * i){
                    if(nf >= i){
                        df = i;
                    }
                }

                for(int i = 2; i <= df; i = 2 * i){
                    for(int tx = 0; tx < NUMBER_THREADS; tx++){
                        if((tx + 1) % i == 0 && tx < df){
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                        }
                    }
                }

                int tx_final = df - 1;
                if(tx_final >= 0){
                    for(long i = (long)bx * NUMBER_THREADS + df; i < (long)bx * NUMBER_THREADS + nf; i++){
                        d_psum[tx_final] = d_psum[tx_final] + d_sums[i];
                        d_psum2[tx_final] = d_psum2[tx_final] + d_sums2[i];
                    }
                    d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx_final];
                    d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx_final];
                }
            }
        }
    }
}

void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp d_q0sqr, fp* d_c, fp* d_I){
    #pragma omp parallel for
    for(long ei = 0; ei < d_Ne; ei++){
        int row;
        int col;
        fp d_Jc;
        fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
        fp d_c_loc;
        fp d_G2, d_L, d_num, d_den, d_qsqr;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if((ei + 1) % d_Nr == 0){
            row = d_Nr - 1;
            col = col - 1;
        }

        d_Jc = d_I[ei];
        d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
        d_den = 1 + (0.25 * d_L);
        d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1 + d_q0sqr));
        d_c_loc = 1.0 / (1.0 + d_den);

        if(d_c_loc < 0){
            d_c_loc = 0;
        } else if(d_c_loc > 1){
            d_c_loc = 1;
        }

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp* d_c, fp* d_I){
    #pragma omp parallel for
    for(long ei = 0; ei < d_Ne; ei++){
        int row;
        int col;
        fp d_cN, d_cS, d_cW, d_cE;
        fp d_D;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if((ei + 1) % d_Nr == 0){
            row = d_Nr - 1;
            col = col - 1;
        }

        d_cN = d_c[ei];
        d_cS = d_c[d_iS[row] + d_Nr * col];
        d_cW = d_c[ei];
        d_cE = d_c[row + d_Nr * d_jE[col]];

        d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25 * d_lambda * d_D;
    }
}

void compress_kernel(long d_Ne, fp* d_I){
    #pragma omp parallel for
    for(long ei = 0; ei < d_Ne; ei++){
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

// Wrapper function replacing the OpenCL wrapper
void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI, int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j){

    fp* d_I = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);

    // Copy input image to d_I
    memcpy(d_I, image, sizeof(fp) * Ne);

    // Initial extract
    extract_kernel(Ne, d_I);

    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    int blocks_x = Ne / NUMBER_THREADS;
    if(Ne % NUMBER_THREADS != 0) blocks_x++;
    int blocks_work_size = blocks_x;

    printf("Iterations Progress: hidden");

    for(iter = 0; iter < niter; iter++){
        fflush(stdout);

        // Prepare
        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        // Reduce loop
        long no = Ne;
        int mul = 1;
        int blocks2_work_size = blocks_work_size;

        while(blocks2_work_size != 0){
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if(blocks2_work_size == 1){
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if(blocks2_work_size % NUMBER_THREADS != 0) blocks_x++;
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        // SRAD
        srad_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);

        // SRAD2
        srad2_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW, d_dN, d_dS, d_dW, d_dE, d_c, d_I);
    }

    printf("\n");

    // Compress
    compress_kernel(Ne, d_I);

    // Copy result back
    memcpy(image, d_I, sizeof(fp) * Ne);

    free(d_I);
    free(d_sums);
    free(d_sums2);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
}

int platform_id_inuse = 0;
int device_id_inuse = 0;

int main(int argc, char* argv []){
    printf("WG size of kernel = %d \n", NUMBER_THREADS);

    fp* image_ori;
    int image_ori_rows;
    int image_ori_cols;
    long image_ori_elem;

    fp* image;
    int Nr, Nc;
    long Ne;

    int niter;
    fp lambda;

    int r1, r2, c1, c2;
    long NeROI;

    int* iN;
    int* iS;
    int* jE;
    int* jW;

    int iter;
    long i;
    long j;

    int mem_size_i;
    int mem_size_j;

    int cur_arg;
    // Default values if not provided to avoid uninitialized usage
    niter = 1; 
    lambda = 1.0;
    Nr = 502;
    Nc = 458;

    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                niter = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                lambda = (fp)atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 3) {
                Nr = atoi(argv[cur_arg+1]);
                Nc = atoi(argv[cur_arg+2]);
                cur_arg = cur_arg + 2;
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

    image_ori_rows = 502;
    image_ori_cols = 458;
    image_ori_elem = image_ori_rows * image_ori_cols;

    image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

    read_graphics_local("../../data/srad/image.pgm", image_ori, image_ori_rows, image_ori_cols, 1);

    Ne = (long)Nr * Nc;
    image = (fp*)malloc(sizeof(fp) * Ne);

    resize_local(image_ori, image_ori_rows, image_ori_cols, image, Nr, Nc, 1);

    r1 = 0;
    r2 = Nr - 1;
    c1 = 0;
    c2 = Nc - 1;

    NeROI = (long)(r2 - r1 + 1) * (c2 - c1 + 1);

    mem_size_i = sizeof(int) * Nr;
    iN = (int *)malloc(mem_size_i);
    iS = (int *)malloc(mem_size_i);
    mem_size_j = sizeof(int) * Nc;
    jW = (int *)malloc(mem_size_j);
    jE = (int *)malloc(mem_size_j);

    for (i = 0; i < Nr; i++) {
        iN[i] = i - 1;
        iS[i] = i + 1;
    }
    for (j = 0; j < Nc; j++) {
        jW[j] = j - 1;
        jE[j] = j + 1;
    }

    iN[0] = 0;
    iS[Nr - 1] = Nr - 1;
    jW[0] = 0;
    jE[Nc - 1] = Nc - 1;

    kernel_gpu_opencl_wrapper(image, Nr, Nc, Ne, niter, lambda, NeROI, iN, iS, jE, jW, iter, mem_size_i, mem_size_j);

    write_graphics_local("./output/image_out.pgm", image, Nr, Nc, 1, 255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}

#include "./main.h"
