// Inline definitions from support headers
#define fp float

#ifdef RD_WG_SIZE_0_0
        #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define NUMBER_THREADS RD_WG_SIZE
#else
        #define NUMBER_THREADS 256
#endif

// Helper for timing if needed
void tvsub(struct timeval *tout, struct timeval *tin, struct timeval *tdiff) {
    tdiff->tv_sec = tout->tv_sec - tin->tv_sec;
    tdiff->tv_usec = tout->tv_usec - tin->tv_usec;
    if (tdiff->tv_usec < 0) {
        tdiff->tv_sec--;
        tdiff->tv_usec += 1000000;
    }
}

// Graphics functions inline
void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range) {
    FILE* fid;
    int i, j;
    fid = fopen(filename, "w");
    if( fid == NULL ){
        printf( "The file was not created/opened for writing\n" );
        return;
    }
    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[i*data_cols+j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%d ", (int)input[j*data_rows+i]);
            }
            fprintf(fid, "\n");
        }
    }
    fclose(fid);
}

void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major) {
    FILE* fid;
    int i, j;
    char c;
    int temp;
    fid = fopen(filename, "r");
    if( fid == NULL ){
        printf( "The file was not opened for reading\n" );
        return;
    }
    i = 0;
    while(i<3){
        c = fgetc(fid);
        if(c == '\n'){
            i = i+1;
        }
    }
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[i*data_cols+j] = (fp)temp;
            }
        }
    } else {
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%d", &temp);
                input[j*data_rows+i] = (fp)temp;
            }
        }
    }
    fclose(fid);
}

void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major) {
    int i, j;
    int i2, j2;
    if(major == 0){
        for(i=0, i2=0; i<output_rows; i++, i2++){
            if(i2>=input_rows){ i2 = i2 - input_rows; }
            for(j=0, j2=0; j<output_cols; j++, j2++){
                if(j2>=input_cols){ j2 = j2 - input_cols; }
                output[i*output_cols+j] = input[i2*input_cols+j2];
            }
        }
    } else {
        for(j=0, j2=0; j<output_cols; j++, j2++){
            if(j2>=input_cols){ j2 = j2 - input_cols; }
            for(i=0, i2=0; i<output_rows; i++, i2++){
                if(i2>=input_rows){ i2 = i2 - input_rows; }
                output[j*output_rows+i] = input[j2*input_rows+i2];
            }
        }
    }
}

// Wrapper function
void 
kernel_gpu_opencl_wrapper(	fp* image,											
							int Nr,												
							int Nc,												
							long Ne,											
							int niter,											
							fp lambda,											
							long NeROI,											
							int* iN,
							int* iS,
							int* jW,
							int* jE,
							int iter,											
							int mem_size_i,
							int mem_size_j)
{

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
                d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int blocks_x;
    long mem_size = sizeof(fp) * Ne;												

    fp* d_I = (fp*)malloc(mem_size);
    int* d_iN_int = (int*)malloc(mem_size_i);
    int* d_iS_int = (int*)malloc(mem_size_i);
    int* d_jE_int = (int*)malloc(mem_size_j);
    int* d_jW_int = (int*)malloc(mem_size_j);

    memcpy(d_iN_int, iN, mem_size_i);
    memcpy(d_iS_int, iS, mem_size_i);
    memcpy(d_jE_int, jE, mem_size_j);
    memcpy(d_jW_int, jW, mem_size_j);

    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);
    fp* d_c = (fp*)malloc(mem_size);
    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);

    // H2D
    memcpy(d_I, image, mem_size);

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_mem_alloc_end, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    blocks_x = Ne / NUMBER_THREADS;
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x += 1;
    }
    int blocks_work_size = blocks_x;

    printf("max # of workgroups = %d, # of threads/workgroup = %d\n", blocks_work_size, NUMBER_THREADS);

    // Extract Kernel
    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ++ei) {
        d_I[ei] = exp(d_I[ei] / 255.0);
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    // Prepare Kernel
    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ++ei) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }

    // Reduce Logic
    long no = Ne;
    int mul = 1;
    int blocks2_work_size = blocks_work_size;

    while (blocks2_work_size != 0) {
        long current_no = no;
        int current_blocks = blocks2_work_size;

        #pragma omp parallel for
        for (int bx = 0; bx < current_blocks; ++bx) {
            fp local_psum[NUMBER_THREADS];
            fp local_psum2[NUMBER_THREADS];

            int nf = NUMBER_THREADS - (current_blocks * NUMBER_THREADS - current_no);
            int df = 0;

            for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                long ei = (long)bx * NUMBER_THREADS + tx;
                if (ei < current_no) {
                    local_psum[tx] = d_sums[ei * mul];
                    local_psum2[tx] = d_sums2[ei * mul];
                } else {
                    local_psum[tx] = 0.0;
                    local_psum2[tx] = 0.0;
                }
            }

            if (nf == NUMBER_THREADS) {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                        if ((tx + 1) % i == 0) {
                            local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                            local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                        }
                    }
                }
                if (NUMBER_THREADS > 0) {
                    d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[NUMBER_THREADS - 1];
                    d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[NUMBER_THREADS - 1];
                }
            } else {
                if (bx != (current_blocks - 1)) {
                    for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                        for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                            if ((tx + 1) % i == 0) {
                                local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                                local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                            }
                        }
                    }
                    if (NUMBER_THREADS > 0) {
                        d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[NUMBER_THREADS - 1];
                        d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[NUMBER_THREADS - 1];
                    }
                } else {
                    for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                        if (nf >= i) {
                            df = i;
                        }
                    }

                    for (int i = 2; i <= df; i = 2 * i) {
                        for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                            if ((tx + 1) % i == 0 && tx < df) {
                                local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                                local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                            }
                        }
                    }

                    if (df > 0) {
                        int tx = df - 1;
                        for (long i_idx = ((long)bx * NUMBER_THREADS) + df; i_idx < ((long)bx * NUMBER_THREADS) + nf; i_idx++) {
                            local_psum[tx] = local_psum[tx] + d_sums[i_idx];
                            local_psum2[tx] = local_psum2[tx] + d_sums2[i_idx];
                        }
                        d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[tx];
                        d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[tx];
                    }
                }
            }
        }

        no = blocks2_work_size;
        if (blocks2_work_size == 1) {
            blocks2_work_size = 0;
        } else {
            mul = mul * NUMBER_THREADS;
            blocks_x = blocks2_work_size / NUMBER_THREADS;
            if (blocks2_work_size % NUMBER_THREADS != 0) {
                blocks_x = blocks_x + 1;
            }
            blocks2_work_size = blocks_x;
        }
    }

    fp total = d_sums[0];
    fp total2 = d_sums2[0];

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    fp meanROI = total / (fp)(NeROI);
    fp meanROI2 = meanROI * meanROI;
    fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
    fp q0sqr = varROI / meanROI2;

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            d_sums[ei] = d_I[ei];
            d_sums2[ei] = d_I[ei] * d_I[ei];
        }

        no = Ne;
        mul = 1;
        blocks2_work_size = blocks_work_size;

        while (blocks2_work_size != 0) {
            long current_no = no;
            int current_blocks = blocks2_work_size;

            #pragma omp parallel for
            for (int bx = 0; bx < current_blocks; ++bx) {
                fp local_psum[NUMBER_THREADS];
                fp local_psum2[NUMBER_THREADS];

                int nf = NUMBER_THREADS - (current_blocks * NUMBER_THREADS - current_no);
                int df = 0;

                for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                    long ei = (long)bx * NUMBER_THREADS + tx;
                    if (ei < current_no) {
                        local_psum[tx] = d_sums[ei * mul];
                        local_psum2[tx] = d_sums2[ei * mul];
                    } else {
                        local_psum[tx] = 0.0;
                        local_psum2[tx] = 0.0;
                    }
                }

                if (nf == NUMBER_THREADS) {
                    for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                        for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                            if ((tx + 1) % i == 0) {
                                local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                                local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                            }
                        }
                    }
                    if (NUMBER_THREADS > 0) {
                        d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[NUMBER_THREADS - 1];
                        d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[NUMBER_THREADS - 1];
                    }
                } else {
                    if (bx != (current_blocks - 1)) {
                        for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                            for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                                if ((tx + 1) % i == 0) {
                                    local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                                    local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                                }
                            }
                        }
                        if (NUMBER_THREADS > 0) {
                            d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[NUMBER_THREADS - 1];
                            d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[NUMBER_THREADS - 1];
                        }
                    } else {
                        for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                            if (nf >= i) {
                                df = i;
                            }
                        }

                        for (int i = 2; i <= df; i = 2 * i) {
                            for (int tx = 0; tx < NUMBER_THREADS; ++tx) {
                                if ((tx + 1) % i == 0 && tx < df) {
                                    local_psum[tx] = local_psum[tx] + local_psum[tx - i / 2];
                                    local_psum2[tx] = local_psum2[tx] + local_psum2[tx - i / 2];
                                }
                            }
                        }

                        if (df > 0) {
                            int tx = df - 1;
                            for (long i_idx = ((long)bx * NUMBER_THREADS) + df; i_idx < ((long)bx * NUMBER_THREADS) + nf; i_idx++) {
                                local_psum[tx] = local_psum[tx] + d_sums[i_idx];
                                local_psum2[tx] = local_psum2[tx] + d_sums2[i_idx];
                            }
                            d_sums[(long)bx * mul * NUMBER_THREADS] = local_psum[tx];
                            d_sums2[(long)bx * mul * NUMBER_THREADS] = local_psum2[tx];
                        }
                    }
                }
            }

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) {
                    blocks_x = blocks_x + 1;
                }
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        // SRAD Kernel
        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            int row = (ei + 1) % Nr - 1;
            int col = (ei + 1) / Nr + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_Jc = d_I[ei];
            fp d_dN_loc = d_I[d_iN_int[row] + (long)Nr * col] - d_Jc;
            fp d_dS_loc = d_I[d_iS_int[row] + (long)Nr * col] - d_Jc;
            fp d_dW_loc = d_I[row + (long)Nr * d_jW_int[col]] - d_Jc;
            fp d_dE_loc = d_I[row + (long)Nr * d_jE_int[col]] - d_Jc;

            fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
            fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            fp d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
            fp d_den = 1.0 + (0.25 * d_L);
            fp d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - q0sqr) / (q0sqr * (1.0 + q0sqr));
            fp d_c_loc = 1.0 / (1.0 + d_den);

            if (d_c_loc < 0) d_c_loc = 0;
            else if (d_c_loc > 1) d_c_loc = 1;

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }

        // SRAD2 Kernel
        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            int row = (ei + 1) % Nr - 1;
            int col = (ei + 1) / Nr + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_cN = d_c[ei];
            fp d_cS = d_c[d_iS_int[row] + (long)Nr * col];
            fp d_cW = d_c[ei];
            fp d_cE = d_c[row + (long)Nr * d_jE_int[col]];

            fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + 0.25 * lambda * d_D;
        }
    }

    printf("\n");

    // Compress Kernel
    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ++ei) {
        d_I[ei] = log(d_I[ei]) * 255.0;
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    memcpy(image, d_I, mem_size);

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    free(d_I);
    free(d_iN_int);
    free(d_iS_int);
    free(d_jE_int);
    free(d_jW_int);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
    free(d_sums);
    free(d_sums2);

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

int platform_id_inuse = 0;            
int device_id_inuse = 0;              

int 
main(	int argc, 
		char* argv []){
  printf("WG size of kernel = %d \n", NUMBER_THREADS);

	fp* image_ori;																
	int image_ori_rows;
	int image_ori_cols;
	long image_ori_elem;

	fp* image;															
	int Nr,Nc;													
	long Ne;

	int niter;																
	fp lambda;															

	int r1,r2,c1,c2;												
	long NeROI;														

	int* iN;
	int* iS;
	int* jE;
	int* jW;

	int iter;   
	long i;    
	long j;    

	int mem_size_i;
	int mem_size_j;

    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
		        niter = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
		        lambda = atof(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 3) {
                Nr = atoi(argv[cur_arg+1]);			
        		Nc = atoi(argv[cur_arg+2]);			
                cur_arg += 2;
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	image_ori_rows = 502;
	image_ori_cols = 458;
	image_ori_elem = image_ori_rows * image_ori_cols;

	image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

	read_graphics(	"../../data/srad/image.pgm",
					image_ori,
					image_ori_rows,
					image_ori_cols,
					1);

	Ne = (long)Nr*Nc;

	image = (fp*)malloc(sizeof(fp) * Ne);

	resize(	image_ori,
				image_ori_rows,
				image_ori_cols,
				image,
				Nr,
				Nc,
				1);

	r1     = 0;											
	r2     = Nr - 1;									
	c1     = 0;											
	c2     = Nc - 1;									

	NeROI = (r2-r1+1)*(c2-c1+1);											

	mem_size_i = sizeof(int) * Nr;											
	iN = (int *)malloc(mem_size_i) ;										
	iS = (int *)malloc(mem_size_i) ;										
	mem_size_j = sizeof(int) * Nc;											
	jW = (int *)malloc(mem_size_j) ;										
	jE = (int *)malloc(mem_size_j) ;										

	for (i=0; i<Nr; i++) {
		iN[i] = i-1;														
		iS[i] = i+1;														
	}
	for (j=0; j<Nc; j++) {
		jW[j] = j-1;														
		jE[j] = j+1;														
	}

	iN[0]    = 0;															
	iS[Nr-1] = Nr-1;														
	jW[0]    = 0;															
	jE[Nc-1] = Nc-1;														

	kernel_gpu_opencl_wrapper(	image,										
								Nr,											
								Nc,											
								Ne,											
								niter,										
								lambda,										
								NeROI,										
								iN,
								iS,
								jE,
								jW,
								iter,										
								mem_size_i,
								mem_size_j);

	write_graphics(	"./output/image_out.pgm",
					image,
					Nr,
					Nc,
					1,
					255);

	free(image_ori);
	free(image);
	free(iN); 
	free(iS); 
	free(jW); 
	free(jE);

	return 0;
}

