#endif
#ifdef PROFILE_TMP
  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  time_FL = 0.0;
