}

int isIdentical(float *i, float *j, int D){
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j)
{
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return(0);
}

void shuffle(Points *points)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i=0;i<points->num-1;i++) {
    j=(lrand48()%(points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

void intshuffle(int *intarray, int length)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i=0;i<length;i++) {
    j=(lrand48()%(length - i))+i;
    temp = intarray[i];
    intarray[i]=intarray[j];
    intarray[j]=temp;
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

#ifdef INSERT_WASTE
float waste(float s )
{
  for( int i =0 ; i< 4; i++ ) {
    s += pow(s,0.78);
  }
  return s;
}
#endif

float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  float s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;
  static float totalcost;

  static bool open = false;
  static float* costs; 
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for( int k = k1; k < k2; k++ )    {
    float distance = dist(points->p[k],points->p[0],points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( pid==0 )   {
    *kcenter = 1;
    costs = (float*)malloc(sizeof(float)*nproc);
  }

  if( pid != 0 ) { 
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( i >= points->num ) break;
      for( int k = k1; k < k2; k++ )
      {
        float distance = dist(points->p[i],points->p[k],points->dim);
        if( distance*points->p[k].weight < points->p[k].cost )
        {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign=i;
        }
      }
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    } 
  }
  else  { 
    for(i = 1; i < points->num; i++ )  {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z); 
      if( to_open )  {
        (*kcenter)++;
#ifdef ENABLE_THREADS
        pthread_mutex_lock(&mutex);
#endif
        open = true;
#ifdef ENABLE_THREADS
        pthread_mutex_unlock(&mutex);
        pthread_cond_broadcast(&cond);
#endif
        for( int k = k1; k < k2; k++ )  {	
          float distance = dist(points->p[i],points->p[k],points->dim);
          if( distance*points->p[k].weight < points->p[k].cost )  {
            points->p[k].cost = distance * points->p[k].weight;
            points->p[k].assign=i;
          }
        }
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
        open = false;
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;
  float mytotal = 0;
  for( int k = k1; k < k2; k++ )  {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 )
  {
    totalcost=z*(*kcenter);
    for( int i = 0; i < nproc; i++ )
    {
      totalcost += costs[i];
    } 
    free(costs);
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if( pid == 0 )
  {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
            *kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
  }
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  if( pid== 0 ) {
    time_speedy += t2 -t1;
  }
#endif
  return(totalcost);
}

float pgain(long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
            double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel);

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e, 
          int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i=0;i<iter;i++) {
      x = i%numfeasible;

      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }		
    cost -= change;
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n",
              *k, cost, cost - z*(*k));
    }
#endif
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if (numfeasible > (ITER*kmin*log((float)kmin)))
    numfeasible = (int)(ITER*kmin*log((float)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=k1;i<k2;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; i < points->num; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; i<k2; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;

    l=0;
    r=points->num-1;
    if( accumweight[0] > w )  { 
      (*feasible)[i]=0; 
      continue;
    }
    while( l+1 < r ) {
      k = (l+r)/2;
      if( accumweight[k] > w ) {
        r = k;
      } 
      else {
        l=k;
      }
    }
    (*feasible)[i]=r;
  }
  free(accumweight); 
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
               int pid, pthread_barrier_t* barrier )
{
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static float* hizs;

  if( pid==0 ) hizs = (float*)calloc(nproc,sizeof(float));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 )
  {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
  }
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  float myhiz = 0;
  for (long kk=k1;kk < k2; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0],
                  ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS  
  pthread_barrier_wait(barrier);
#endif

  for( int i = 0; i < nproc; i++ )   {
    hiz += hizs[i];
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {	

    for (long kk=k1;kk<k2;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid== 0 ) {
      free(hizs); 
      *kfinal = k;
    }
    return cost;
  }

  if( pid == 0 ) shuffle(points);	
  cost = pspeedy(points, z, &k, pid, barrier);
#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((k < kmin)&&(i<SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif 

  while (k < kmin) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 )
  {
    numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier); 
    for( int i = 0; i< points->num; i++ ) {
      is_center[points->p[i].assign]= true;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while(1) {
#ifdef PRINTINFO
    if( pid==0 )
    {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1)*kmax)&&(k >= (0.9)*kmin))||
        ((k <= kmax+2)&&(k >= kmin-2))) {
#ifdef PRINTINFO
      if( pid== 0)
      {
        printf("Trying a more accurate local search...\n");
      }
#endif

      cost = pFL(points, feasible, numfeasible,
                 z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost += (z-loz)*k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost += (z-hiz)*k;
    }

    if (((k <= kmax)&&(k >= kmin))||((loz >= (0.999)*hiz)) )
    { 
      break;
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if( pid==0 ) {
    free(feasible); 
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {

    if (points->p[i].assign != i) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;

      relweight = points->p[i].weight/relweight;
      for (ii=0;ii<points->dim;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+=
        points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; i < points->num; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; i < points->num; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);

  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier,NULL,nproc);
#endif
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for( int i = 0; i < nproc; i++ ) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;

    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads+i,NULL,localSearchSub,(void*)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for ( int i = 0; i < nproc; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i],NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2-t1;
#endif
}

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; i< centers->num; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; i < centers->num; i++ ) {
    if( is_a_median[i] ) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for( int k = 0; k < centers->dim; k++ ) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

void streamCluster( PStream* stream, 
                    long kmin, long kmax, int dim,
                    long chunksize, long centersize, char* outfile )
{

  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) { 
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; i < chunksize; i++ ) {
    points.p[i].coord = &block[i*dim];		
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; i< centersize; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {

    size_t numRead  = stream->read(block, dim, chunksize ); 
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( kfinal + centers.num > centersize ) {
      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n"); 
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);
}

// OpenMP implementation of pgain_kernel logic
void pgain_kernel_omp(
    Point_Struct *p,
    float *coord_d,
    float * work_mem_d,
    int *center_table_d,
    char *switch_membership_d,
    int num,
    int dim,
    long x,
    int K)
{
    // Allocate temporary storage for the center coordinates (x)
    // In OpenCL this was local memory, here we use a vector or array
    std::vector<float> coord_s(dim);

    // Copy coordinates of point x to coord_s
    // This corresponds to the local_id == 0 block in OpenCL
    for(int i=0; i<dim; i++){ 
        coord_s[i] = coord_d[i*num + x];
    }

    // Parallel loop over all points (thread_id in OpenCL)
    #pragma omp parallel for
    for(int thread_id = 0; thread_id < num; thread_id++) {

        // Calculate distance cost to x
        float x_cost = 0.0;
        for(int i=0; i<dim; i++)
            x_cost += (coord_d[(i*num)+thread_id]-coord_s[i]) * (coord_d[(i*num)+thread_id]-coord_s[i]);
        x_cost = x_cost * p[thread_id].weight;

        float current_cost = p[thread_id].cost;

        int base = thread_id*(K+1);	 

        if ( x_cost < current_cost ){
            switch_membership_d[thread_id] = '1';
            int addr_1 = base + K;
            work_mem_d[addr_1] = x_cost - current_cost;
        }
        else {
            int assign = p[thread_id].assign;
            int addr_2 = base + center_table_d[assign];
            work_mem_d[addr_2] += current_cost - x_cost;
        }
    }
}

// OpenMP implementation of memset_kernel logic
void memset_kernel_omp(char * mem_d, short val, int number_bytes){
    #pragma omp parallel for
    for(int i = 0; i < number_bytes; i++) {
        mem_d[i] = (char)val;
    }
}

float pgain( long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
             double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
    float gl_cost = 0;

    int K	= *numcenters ;						
    int num    =   points->num;				
    int dim     =   points->dim;				
    kmax++;

    int count = 0;
    for( int i=0; i<num; i++){
        if( is_center[i] )
            center_table[i] = count++;
    }

#ifdef PROFILE_TMP
    double t1 = gettime();
#endif

    // Allocate host memory structures if not already done (simulating the 'c == 0' block)
    // Since we are translating to pure OpenMP, we don't need GPU buffers.
    // We will use direct pointers to the data in 'points' or temporary arrays.

    // Prepare data structures for the OpenMP kernel
    // We need a flat array for coordinates similar to coord_d in OpenCL: [dim][num] -> actually [num][dim] or [dim*num]
    // The OpenCL code uses coord_d[(i*num)+thread_id], which implies layout: dim * num, where index is (dim_idx * num + point_idx)

    float *coord_d = (float*)malloc(num * dim * sizeof(float));
    for(int i=0; i<dim; i++){
        for(int j=0; j<num; j++)
            coord_d[ (i*num)+j ] = points->p[j].coord[i];
    }

    Point_Struct *p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));
    for(int i=0; i<num; i++){
        p_h[i].weight = ((points->p)[i]).weight;
        p_h[i].assign = ((points->p)[i]).assign;
        p_h[i].cost = ((points->p)[i]).cost;	
    }

    // work_mem_d layout: num * (K+1)
    float *work_mem_d = (float*)calloc(num * (K+1), sizeof(float));

    // Initialize switch_membership to 0
    memset_kernel_omp(switch_membership, 0, num);
    // work_mem_d is already 0 via calloc, but explicit call if needed:
    // memset_kernel_omp((char*)work_mem_d, 0, num*(K+1)*sizeof(float)); // Not strictly needed if calloc used

#ifdef PROFILE_TMP
    double t9 = gettime();
#endif

    // Execute the parallel kernel
    pgain_kernel_omp(p_h, coord_d, work_mem_d, center_table, switch_membership, num, dim, x, K);

#ifdef PROFILE_TMP
    double t10 = gettime();
    *kernel += t10 - t9;
#endif

    // Post-processing (same as original)
    int numclose = 0;
    gl_cost = z;

    float *gl_lower = (float*)calloc(kmax, sizeof(float));

    for(int i=0; i < num; i++){	
        if( is_center[i] ) {
            float low = z;

            for( int j = 0; j < num; j++ )
                low += work_mem_d[ j*(K+1) + center_table[i] ];

            gl_lower[center_table[i]] = low;

            if ( low > 0 ) {
                numclose++;				
                work_mem_d[i*(K+1)+K] -= low;
            }
        }
        gl_cost += work_mem_d[i*(K+1)+K];
    }

    if ( gl_cost < 0 ) {
        for(int i=0; i<num; i++){

            bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
            if ( (switch_membership[i]=='1') || close_center ) {
                points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
                points->p[i].assign = x;
            }
        }

        for(int i=0; i<num; i++){
            if( is_center[i] && gl_lower[center_table[i]] > 0 )
                is_center[i] = false;
        }

        is_center[x] = true;
        *numcenters = *numcenters +1 - numclose;
    }
    else
        gl_cost = 0;  

#ifdef PROFILE_TMP
    double t12 = gettime();
    *serial += t12 - t10;
#endif

    // Cleanup temporary arrays
    free(coord_d);
    free(p_h);
    free(work_mem_d);
    free(gl_lower);

    return -gl_cost;
}

