  }
  fclose(fp);
}

void streamCluster( PStream* stream, 
		    long kmin, long kmax, int dim,
		    long chunksize, long centersize, char* outfile )
{
  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) { 
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; chunksize > i; i++ ) {
    points.p[i].coord = &block[i*dim];		
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; centersize > i; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {
    size_t numRead  = stream->read(block, dim, chunksize ); 
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    #pragma omp parallel for
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( centersize < kfinal + centers.num ) {
      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n"); 
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);

  free(block);
  free(centerBlock);
  free(centerIDs);
  free(points.p);
  free(centers.p);
}

// OpenMP implementation of pgain_kernel logic
float pgain( long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
             double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
  float gl_cost = 0;

#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  int K	= *numcenters ;						
  int num    =   points->num;				
  int dim     =   points->dim;				
  kmax++;

  int count = 0;
  #pragma omp parallel for
  for( int i=0; i<num; i++){
    if( is_center[i] )
      center_table[i] = count++;
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  *serial += t2 - t1;
#endif

  static float *coord_h = NULL;
  static float *gl_lower = NULL;
  static Point_Struct *p_h = NULL;
  static float *work_mem_h = NULL;
  static bool initialized = false;

  if( !initialized ) {
#ifdef PROFILE_TMP
    double t3 = gettime();
#endif
    coord_h = (float*) malloc( num * dim * sizeof(float));								
    gl_lower = (float*) malloc( kmax * sizeof(float) );
    work_mem_h = (float*)malloc(kmax*num*sizeof(float));
    p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));	

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    #pragma omp parallel for
    for(int i=0; i<dim; i++){
      for(int j=0; j<num; j++)
        coord_h[ (num*i)+j ] = points->p[j].coord[i];
    }
#ifdef PROFILE_TMP		
    double t4 = gettime();
    *serial += t4 - t3;
#endif
#ifdef PROFILE_TMP
    double t5 = gettime();
    *gpu_malloc += t5 - t4;
#endif
    initialized = true;
  }	

#ifdef PROFILE_TMP
  double t100 = gettime();
#endif

  #pragma omp parallel for
  for(int i=0; i<num; i++){
    p_h[i].weight = ((points->p)[i]).weight;
    p_h[i].assign = ((points->p)[i]).assign;
    p_h[i].cost = ((points->p)[i]).cost;	
  }

#ifdef PROFILE_TMP
  double t101 = gettime();
  *serial += t101 - t100;
#endif

#ifdef PROFILE_TMP
  double t7 = gettime();
#endif

  // Simulate memcpy overhead if needed, but data is already in shared memory
#ifdef PROFILE_TMP
  double t8 = gettime();
  *cpu_gpu_memcpy += t8 - t7;
#endif

#ifdef PROFILE_TMP
  double t9 = gettime();
#endif

  // memset simulation
  #pragma omp parallel for
  for(int i=0; i<num; i++) switch_membership[i] = 0;
  #pragma omp parallel for
  for(int i=0; i<(K+1)*num; i++) work_mem_h[i] = 0.0f;

  // Kernel logic translated to OpenMP
  #pragma omp parallel
  {
    int thread_id = omp_get_thread_num();
    int num_threads = omp_get_num_threads();

    // Local copy of coord for x (simulating local memory)
    float coord_s[dim];
    if (thread_id == 0) {
      for(int i=0; i<dim; i++){ 
        coord_s[i] = coord_h[i*num + x];
      }
    }
    #pragma omp barrier

    #pragma omp for
    for(int tid = 0; tid < num; tid++) {
      float x_cost = 0.0;
      for(int i=0; i<dim; i++)
        x_cost += (coord_h[(i*num)+tid]-coord_s[i]) * (coord_h[(i*num)+tid]-coord_s[i]);
      x_cost = x_cost * p_h[tid].weight;

      float current_cost = p_h[tid].cost;
      int base = tid*(K+1);	 

      if ( x_cost < current_cost ){
        switch_membership[tid] = '1';
        int addr_1 = base + K;
        work_mem_h[addr_1] = x_cost - current_cost;
      }
      else {
        int assign = p_h[tid].assign;
        int addr_2 = base + center_table[assign];
        work_mem_h[addr_2] += current_cost - x_cost;
      }
    }
  }

  #ifdef PROFILE_TMP
  double t10 = gettime();
  *kernel += t10 - t9;
#endif

  // Copy back simulation (data is already in work_mem_h and switch_membership)
#ifdef PROFILE_TMP
  double t11 = gettime();
  *memcpy_back += t11 - t10;
#endif

  int numclose = 0;
  gl_cost = z;

  #pragma omp parallel for reduction(+:gl_cost) reduction(+:numclose)
  for(int i=0; i < num; i++){	
    if( is_center[i] ) {
      float low = z;
      for( int j = 0; j < num; j++ )
        low += work_mem_h[ j*(K+1) + center_table[i] ];

      gl_lower[center_table[i]] = low;

      if ( low > 0 ) {
        numclose++;				
        work_mem_h[i*(K+1)+K] -= low;
      }
    }
    gl_cost += work_mem_h[i*(K+1)+K];
  }

  if ( gl_cost < 0 ) {
    #pragma omp parallel for
    for(int i=0; i<num; i++){
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
      if ( (switch_membership[i]=='1') || close_center ) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    #pragma omp parallel for
    for(int i=0; i<num; i++){
      if( is_center[i] && gl_lower[center_table[i]] > 0 )
        is_center[i] = false;
    }

    is_center[x] = true;
    *numcenters = *numcenters +1 - numclose;
  }
  else
    gl_cost = 0;  

#ifdef PROFILE_TMP
  double t12 = gettime();
  *serial += t12 - t11;
#endif

  return -gl_cost;
}

